import { useState, useEffect, useRef, Component } from "react";
import { WidgetBridge } from "./plugins/widgetBridge";
import { integrationBridge } from "./plugins/integrationBridge";
import { DisruptorTool } from "./disruptor/DisruptorTool";
import { MoveCardTool } from "./move-card/MoveCardTool.jsx";
import { MoveCardPill } from "./move-card/MoveCardPill.jsx";
import { PracticeSurface } from "./practice-surface/PracticeSurface.jsx";
import { PracticeEvidenceRatification } from "./practice-evidence/PracticeEvidenceRatification.jsx";

class ErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  componentDidCatch(error, info) {
    console.error("Stillform error:", error, info);
    // Persist a single most-recent crash record. Picked up by the next
    // App Diagnostics snapshot (existing opt-in metrics-ingest pipeline)
    // and cleared after successful send. No new infrastructure — rides the
    // diagnostics flow the user has already opted into.
    try {
      localStorage.setItem("stillform_last_error", JSON.stringify({
        timestamp: new Date().toISOString(),
        message: String(error?.message || error || "unknown"),
        stack: String(error?.stack || "").slice(0, 2000),
        componentStack: String(info?.componentStack || "").slice(0, 1000)
      }));
    } catch {}
  }
  render() {
    if (this.state.error) {
      // Use CSS variables so the boundary respects whichever theme the user has set
      // (dark, midnight, suede, teal, rose, light). Themes set --amber etc. on
      // document.documentElement so they're available even when React's tree errors out.
      //
      // May 7, 2026: added "Clear local data & restart" recovery path. The original boundary
      // had only a plain reload — fine for transient crashes, but if the crash is caused by
      // corrupted localStorage (broken JSON, schema mismatch, partial writes from an interrupted
      // sync) the user loops back into the same crash on every reload. The clear-local path
      // wipes all stillform_* keys but keeps the Supabase auth session intact, so the user
      // stays signed in and cloud sync restores the data layer on the next launch. Doesn't
      // touch the cloud — only local. Confirms before running because this path drops any
      // local writes that haven't synced up yet (rare but possible).
      const handleClearAndRestart = () => {
        const confirmed = window.confirm(
          "Clear local data and restart?\n\n" +
          "This wipes saved data on this device only. If you're signed in to Cloud Sync, " +
          "your data will be restored from the cloud automatically when the app reloads.\n\n" +
          "Use this if restarting alone keeps crashing."
        );
        if (!confirmed) return;
        try {
          Object.keys(localStorage).forEach((key) => {
            if (key.startsWith("stillform_") && key !== "stillform_sb_session") {
              localStorage.removeItem(key);
            }
          });
        } catch {}
        this.setState({ error: null });
        window.location.href = "/";
      };
      return (
        <div style={{ background: "var(--bg, #08080A)", color: "var(--text, #E8EAF0)", padding: 40, minHeight: "100vh", fontFamily: "'DM Sans', sans-serif", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center" }}>
          <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 32, fontWeight: 300, color: "var(--amber, #B8862B)", marginBottom: 12 }}>Something went wrong.</div>
          <div style={{ fontSize: 14, color: "var(--text-muted, #9496A1)", marginBottom: 16, lineHeight: 1.6 }}>Your data is safe. Tap below to restart.</div>
          <button onClick={() => { this.setState({ error: null }); window.location.href = "/"; }}
            style={{ background: "var(--surface, #111114)", color: "var(--amber, #B8862B)", border: "0.5px solid color-mix(in srgb, var(--amber, #B8862B) 50%, transparent)", padding: "14px 28px", cursor: "pointer", borderRadius: 4, fontSize: 14, fontWeight: 400 }}>
            Restart Stillform
          </button>
          <button onClick={handleClearAndRestart}
            style={{ background: "transparent", color: "var(--text-muted, #9496A1)", border: "none", padding: "12px 16px", marginTop: 12, cursor: "pointer", fontSize: 12, fontWeight: 400, textDecoration: "underline" }}>
            Still crashing? Clear local data &amp; restart
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}


const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400&family=DM+Sans:wght@300;400;500&family=IBM+Plex+Mono:wght@300;400&display=swap');

  * { margin: 0; padding: 0; box-sizing: border-box; -webkit-user-select: none; user-select: none; }
  input, textarea { -webkit-user-select: text; user-select: text; }

  :root {
    /* GROUNDS — surface matches bg so default cards read as bordered-on-ground
       (Aesop/MUBI/Espresso convention). The --ground-elev tokens exist for
       situations that genuinely need elevation (modals, inputs, nested forms),
       not for default cards. Apr 30 design system spec confirms both:
       "instrument cards" on ground with hairlines, "modals/nested" on elev. */
    --bg:           #08080A;
    --surface:      #08080A;   /* default surface = ground (cards on ground) */
    --surface2:     #0C0C10;   /* whisper-above for inset stats */
    --ground-elev:  #111114;   /* genuine elevation: modals, primary inputs */
    --ground-elev-2:#16161A;   /* secondary elevation: nested inputs in modals */

    /* BORDERS — hairline, printed-not-drawn */
    --border:         rgba(255,255,255,0.06);
    --border-hi:      rgba(255,255,255,0.10);
    --border-printed: rgba(255,255,255,0.04);
    /* Spec-aliased names for design-system-aware components */
    --border-hairline: var(--border);
    --border-emphasis: var(--border-hi);

    /* ACCENT — antiqued metallic, used at <5% of any screen, never as fill */
    --amber:      #B8862B;
    --amber-dim:  rgba(184,134,43,0.35);
    --amber-glow: rgba(184,134,43,0.06);
    --amber-20:   rgba(184,134,43,0.20);
    --amber-deep: #8C6420;
    /* Spec-aliased names */
    --accent:      var(--amber);
    --accent-deep: var(--amber-deep);
    --accent-glow: var(--amber-glow);
    --accent-line: var(--amber-dim);

    /* TEXT — cream-on-black for editorial, primary white for system */
    --text:       #E8EAF0;
    --text-cream: #EDE8DC;
    --text-dim:   rgba(232,234,240,0.62);
    --text-muted: rgba(232,234,240,0.40);
    /* Spec-aliased names — design-system-aware components can use either */
    --text-primary: var(--text);
    --text-quiet:   var(--text-dim);
    --text-faint:   var(--text-muted);

    /* STATE — subtle tonal shifts, never bold */
    --state-positive: #8FA88A;
    --state-negative: #B47A6A;
    --state-neutral:  #A8A29A;

    /* legacy aliases */
    --green:      #8FA88A;
    --green-glow: rgba(143,168,138,0.08);

    /* RADIUS — tighter, printed feel; aligned with design system spec 2/4/6 */
    --r-tight:    2px;     /* inputs, small buttons, status pills */
    --r-default:  4px;     /* cards, primary buttons */
    --r-large:    6px;     /* modals, hero containers — used sparingly */
    /* Legacy aliases for existing components — point to spec-correct values */
    --r-sm: var(--r-tight);    /* was 2px — unchanged */
    --r:    var(--r-default);  /* was 3px — now 4 per spec */
    --r-lg: var(--r-large);    /* was 4px — now 6 per spec */

    /* SPACING SCALE — defined rhythm, no arbitrary values */
    --space-2: 2px;
    --space-4: 4px;
    --space-8: 8px;
    --space-12: 12px;
    --space-16: 16px;
    --space-24: 24px;
    --space-32: 32px;
    --space-48: 48px;
    --space-64: 64px;
    --space-80: 80px;

    /* MOTION — weighted, ceremonial timing */
    --motion-quick:    180ms;
    --motion-default:  300ms;
    --motion-weighted: 480ms;
    --motion-slow:     650ms;
    --ease-prestige:   cubic-bezier(0.22, 0.61, 0.36, 1);
    --ease-page-turn:  cubic-bezier(0.32, 0.08, 0.24, 1);
    --ease-shutter:    cubic-bezier(0.55, 0.06, 0.68, 0.19);
  }

  html, body, #root {
    height: 100%;
    /* Cinematic depth via barely-visible radial gradient at center.
       Per spec: "saturated dark with subtle dimensionality" (Linear, Hermès).
       2% lightness shift toward center, transparent past 60%. Body is not
       flat #08080A; it has the slightest center-glow on ground. */
    background:
      radial-gradient(ellipse at 50% 30%, rgba(255,255,255,0.018) 0%, transparent 60%),
      var(--bg);
    /* Mac-only crispness — forces grayscale antialiasing instead of subpixel.
       Subpixel rendering produces RGB color fringes on glyphs that fight with
       any non-solid background (gradients, transparency) and read as 'blurry'
       on Mac. iOS already uses grayscale by default; these properties have no
       effect on mobile. */
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
  }

  .app {
    min-height: 100vh;
    background: var(--bg);
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-weight: 400;
    position: relative;
    overflow-x: hidden;
    /* Grain texture removed Apr 30 — was disrupting subpixel rendering on Mac and adding nothing on phone.
       References (Aesop, Hermès, MUBI, Linear) use no grain; depth comes from the radial gradient alone. */
  }

  /* Button color reset (May 12, 2026).
     HTML <button> elements have a User-Agent default style of color: ButtonText
     — a system color that does NOT inherit from the parent cascade. On dark
     backgrounds in iOS Safari and mobile Chrome, ButtonText resolves to near-black
     and renders as invisible text on near-black surfaces. Forcing color: inherit
     makes buttons inherit from .app (var(--text), light-on-dark).
     Buttons that set their own color in inline style or className override this
     reset — the fix only catches buttons that didn't set a color. */
  button {
    color: inherit;
  }

  .app::before {
    /* Cinematic radial — single depth effect, slightly strengthened to compensate for grain removal.
       Reference: Linear's deep-blue-black with ~2% radial lightness shift toward center. */
    content: '';
    position: fixed;
    top: -30%;
    left: -10%;
    width: 100%;
    height: 100%;
    background: radial-gradient(ellipse at 50% 30%, rgba(255,255,255,0.025) 0%, transparent 70%);
    pointer-events: none;
    z-index: 0;
  }

  /* TYPOGRAPHIC SCALE — use these utility classes, do not invent sizes */
  .t-display-xl { font-family: 'Cormorant Garamond', serif; font-weight: 300; font-size: 48px; line-height: 1.15; letter-spacing: -0.01em; color: var(--text-cream); }
  .t-display-lg { font-family: 'Cormorant Garamond', serif; font-weight: 300; font-size: 36px; line-height: 1.20; letter-spacing: -0.005em; color: var(--text-cream); }
  .t-display-md { font-family: 'Cormorant Garamond', serif; font-weight: 400; font-size: 28px; line-height: 1.30; }
  .t-display-sm { font-family: 'Cormorant Garamond', serif; font-weight: 400; font-size: 22px; line-height: 1.35; }
  .t-body-lg    { font-family: 'DM Sans', sans-serif; font-weight: 400; font-size: 17px; line-height: 1.65; }
  .t-body-md    { font-family: 'DM Sans', sans-serif; font-weight: 400; font-size: 15px; line-height: 1.55; }
  .t-body-sm    { font-family: 'DM Sans', sans-serif; font-weight: 400; font-size: 13px; line-height: 1.50; }
  .t-caption    { font-family: 'DM Sans', sans-serif; font-weight: 400; font-size: 12px; line-height: 1.45; letter-spacing: 0.01em; color: var(--text-dim); }
  .t-mono-md    { font-family: 'IBM Plex Mono', monospace; font-weight: 400; font-size: 12px; line-height: 1.40; letter-spacing: 0.06em; text-transform: uppercase; color: var(--text-dim); }
  .t-mono-sm    { font-family: 'IBM Plex Mono', monospace; font-weight: 400; font-size: 10px; line-height: 1.30; letter-spacing: 0.12em; text-transform: uppercase; color: var(--text-dim); }
  .t-mono-xs    { font-family: 'IBM Plex Mono', monospace; font-weight: 400; font-size: 9px;  line-height: 1.20; letter-spacing: 0.16em; text-transform: uppercase; color: var(--text-muted); }

  /* Weight modifiers — spec section 137-139 */
  /* Display headlines: .heavy bumps serif weight from 300 to 400 (display-xl/lg) when more presence needed */
  .t-display-xl.heavy,
  .t-display-lg.heavy { font-weight: 400; }
  /* Body: .strong = medium 500 for emphasis per spec section 139 */
  .t-body-lg.strong,
  .t-body-md.strong,
  .t-body-sm.strong { font-weight: 500; }
  /* Quiet variants — same scale at lower color, for de-emphasized contexts */
  .t-body-lg.quiet,
  .t-body-md.quiet,
  .t-body-sm.quiet { color: var(--text-dim); }
  .t-body-lg.faint,
  .t-body-md.faint,
  .t-body-sm.faint { color: var(--text-muted); }
  .t-display-md.cream,
  .t-display-sm.cream { color: var(--text-cream); }

  /* Italic emphasis — spec section 176: "use almost never. when you do, single word in a sentence — Hermès convention".
     Apply to a span, not a full headline. Cormorant italic is the only legitimate italic in the system. */
  .t-emphasis {
    font-family: 'Cormorant Garamond', serif;
    font-style: italic;
    font-weight: 400;
  }

  /* Prose rhythm — spec section 169: "24px between paragraphs, 40px between sections".
     Wrap a content block in .t-prose; direct child <p> / .t-body-* elements get automatic paragraph rhythm.
     Headlines (.t-display-*) inside .t-prose get more breathing room above (40px to next paragraph). */
  .t-prose > * + * { margin-top: var(--space-24); }
  .t-prose > * + .t-display-xl,
  .t-prose > * + .t-display-lg,
  .t-prose > * + .t-display-md,
  .t-prose > * + .t-display-sm { margin-top: var(--space-48); }
  .t-prose > .t-display-xl + *,
  .t-prose > .t-display-lg + *,
  .t-prose > .t-display-md + *,
  .t-prose > .t-display-sm + * { margin-top: var(--space-24); }
  /* Mono labels stay tight to the headline they precede — Aesop convention */
  .t-prose > .t-mono-sm + .t-display-xl,
  .t-prose > .t-mono-sm + .t-display-lg,
  .t-prose > .t-mono-sm + .t-display-md,
  .t-prose > .t-mono-sm + .t-display-sm,
  .t-prose > .t-mono-xs + .t-display-xl,
  .t-prose > .t-mono-xs + .t-display-lg,
  .t-prose > .t-mono-xs + .t-display-md,
  .t-prose > .t-mono-xs + .t-display-sm { margin-top: var(--space-8); }

  .nav {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px 40px;
    border-bottom: 0.5px solid var(--border);
    position: relative;
    z-index: 10;
  }

  .nav-logo {
    font-family: 'Cormorant Garamond', serif;
    font-weight: 300;
    /* May 12, 2026 — bumped 16px → 18px per Arlin phone test:
       "Stillform is smaller font than Subscribe." Footer is 18px so this
       now matches and the wordmark holds its weight against the nav CTA. */
    font-size: 18px;
    letter-spacing: 0.08em;
    text-transform: none;
    color: var(--text);
    user-select: none;
    -webkit-user-select: none;
  }

  .nav-logo span { color: var(--amber); }

  .nav-actions { display: flex; gap: 12px; align-items: center; }

  .btn {
    padding: 14px 28px;
    border-radius: var(--r-lg);
    font-family: 'DM Sans', sans-serif;
    font-size: 13px;
    font-weight: 400;
    letter-spacing: 0.08em;
    cursor: pointer;
    transition: border-color var(--motion-default) var(--ease-prestige), color var(--motion-default) var(--ease-prestige), background-color var(--motion-default) var(--ease-prestige);
    border: none;
  }

  /* Primary — dignified, not loud. Outline with accent text. Theme-aware. */
  .btn-primary {
    background: var(--surface);
    color: var(--amber);
    border: 0.5px solid color-mix(in srgb, var(--amber) 50%, transparent);
    font-weight: 400;
    box-shadow: inset 0 0.5px 0 rgba(255,255,255,0.025);
  }

  .btn-primary:hover { border-color: var(--amber); color: var(--amber); background: var(--surface2); }
  .btn-primary:active { background: var(--bg); transform: scale(0.985); transition: transform var(--motion-quick) var(--ease-shutter); }

  /* Secondary — quieter outline, neutral text */
  .btn-secondary {
    background: transparent;
    color: var(--text);
    border: 0.5px solid var(--border-hi);
  }

  .btn-secondary:hover { border-color: color-mix(in srgb, var(--amber) 60%, transparent); color: var(--amber); }

  /* Ghost — borderless, subtle */
  .btn-ghost {
    background: transparent;
    color: var(--text-dim);
    border: none;
    padding: 14px 20px;
  }

  .btn-ghost:hover { color: var(--amber); }

  /* COMPONENT VOCABULARY — design system step 3 (Apr 30 spec section 209+) */

  /* Instrument card — when a card is genuinely needed (sessions list, settings).
     Sits with hairline definition + inset top highlight for material depth.
     Spec: bg ground-elev, hairline border, 4px radius, inset top edge, no shadow. */
  .card {
    background: var(--ground-elev);
    border: 0.5px solid var(--border);
    border-radius: var(--r-default);
    padding: var(--space-16);
    box-shadow: inset 0 0.5px 0 rgba(255,255,255,0.025);
  }

  /* Editorial block — single typographic unit, no bg/border, sits on ground.
     Spec: small mono label, large serif headline, body text, optional hairline rule.
     This class applies the spacing rhythm; child elements use t-mono-sm, t-display-md, etc. */
  .editorial-block {
    display: flex;
    flex-direction: column;
    gap: var(--space-12);
    padding: 0;
    background: transparent;
    border: none;
  }
  .editorial-block > .label { /* small mono label */
    font-family: 'IBM Plex Mono', monospace;
    font-weight: 400;
    font-size: 10px;
    line-height: 1.30;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--text-dim);
    margin: 0;
  }
  .editorial-block > .headline { /* serif display */
    font-family: 'Cormorant Garamond', serif;
    font-weight: 400;
    font-size: 28px;
    line-height: 1.30;
    color: var(--text-cream);
    margin: 0;
  }
  .editorial-block > .body {
    font-family: 'DM Sans', sans-serif;
    font-weight: 400;
    font-size: 15px;
    line-height: 1.55;
    color: var(--text);
    margin: 0;
  }

  /* Hairline divider — 0.5px in border-printed. Default full width.
     For Aesop-convention 24-40px centered rule, use .divider.short. */
  .divider {
    border: none;
    border-top: 0.5px solid var(--border-printed);
    margin: var(--space-32) 0;
    width: 100%;
  }
  .divider.short {
    width: 32px;
    margin-left: auto;
    margin-right: auto;
  }
  .divider.accent {
    border-top-color: var(--amber-dim);
  }

  /* Form inputs — instrument feel, not consumer SaaS.
     Tighter radius, hairline border, subtle elevation. */
  .field {
    background: var(--ground-elev);
    border: 0.5px solid var(--border);
    border-radius: var(--r-tight);
    padding: 12px 14px;
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-size: 15px;
    line-height: 1.55;
    width: 100%;
    transition: border-color var(--motion-default) var(--ease-prestige);
  }
  .field:focus {
    outline: none;
    border-color: var(--amber-dim);
  }
  .field::placeholder {
    color: var(--text-muted);
  }

  /* PAGE LAYOUT — spec section 199 page margin discipline.
     Mobile horizontal: 24px. Top: 48-64px below header chrome.
     Bottom: 80px trailing space. Use .page on the screen-level wrapper.
     The .page-hero modifier adds extra top space when the screen leads with a hero headline. */
  .page {
    padding: var(--space-48) var(--space-24) var(--space-80);
    max-width: 100%;
    box-sizing: border-box;
    /* Reading rhythm anchor — body content within .page reads at 52-62 char measure
       per spec section 168. Long-form text inside should use .page-text wrapper. */
  }
  .page-hero {
    padding-top: var(--space-64);
  }
  .page-text {
    /* Constrains body text to 52-62 char measure; reference Aesop, Espresso */
    max-width: 32em;  /* approx 52-62 chars at body-md */
  }
  .page-section {
    /* Vertical rhythm between major sections within a page. Spec section 169:
       40px between sections, 64-80px between major content blocks. */
    margin-top: var(--space-48);
  }
  .page-section.major {
    margin-top: var(--space-64);
  }
  .page-section.minor {
    margin-top: var(--space-32);
  }

  /* HOME */
  .home {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: calc(100vh - 73px);
    padding: 60px 40px;
    text-align: center;
    position: relative;
    z-index: 1;
  }

  .home-tag {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--amber-glow);
    border: 1px solid var(--amber-dim);
    border-radius: 100px;
    padding: 6px 16px;
    font-size: 11px;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: var(--amber);
    margin-bottom: 40px;
  }

  .home-title {
    font-family: 'Cormorant Garamond', serif;
    font-size: clamp(52px, 8vw, 88px);
    font-weight: 300;
    line-height: 1.05;
    letter-spacing: -0.01em;
    margin-bottom: 28px;
    color: var(--text);
  }

  .home-title em {
    font-style: italic;
    color: var(--amber);
  }

  .home-sub {
    font-size: 17px;
    line-height: 1.8;
    color: var(--text-dim);
    max-width: 520px;
    margin-bottom: 48px;
    font-weight: 300;
  }

  .home-cta { display: flex; gap: 12px; flex-wrap: wrap; justify-content: center; margin-bottom: 80px; }

  .home-features {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 16px;
    width: 100%;
    max-width: 860px;
    margin-top: 20px;
  }

  .feature-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 24px;
    text-align: left;
    transition: border-color 0.2s;
  }

  .feature-card:hover { border-color: var(--amber-dim); }

  .feature-icon {
    width: 36px;
    height: 36px;
    background: var(--amber-glow);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 16px;
    font-size: 16px;
  }

  .feature-title { font-size: 14px; font-weight: 500; margin-bottom: 8px; color: var(--text); }
  .feature-desc { font-size: 13px; color: var(--text-dim); line-height: 1.6; }

  /* TOOL SELECTOR */
  .tools {
    max-width: 900px;
    margin: 0 auto;
    padding: 40px 40px 80px;
    position: relative;
    z-index: 1;
  }

  .tools-header { margin-bottom: 40px; }
  .tools-header h2 {
    font-family: 'Cormorant Garamond', serif;
    font-size: 36px;
    font-weight: 300;
    margin-bottom: 8px;
  }
  .tools-header p { color: var(--text-dim); font-size: 14px; }

  .tools-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 16px;
  }

  .tool-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 28px 24px;
    cursor: pointer;
    transition: all 0.2s;
    text-align: left;
  }

  .tool-card:hover {
    border-color: var(--amber-dim);
    background: var(--surface2);
    transform: translateY(-2px);
  }

  .tool-icon { font-size: 28px; margin-bottom: 16px; }
  .tool-name { font-size: 16px; font-weight: 500; margin-bottom: 6px; }
  .tool-desc { font-size: 12px; color: var(--text-dim); line-height: 1.6; }
  .tool-time {
    display: inline-block;
    margin-top: 14px;
    font-size: 11px;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    color: var(--amber);
    background: var(--amber-glow);
    padding: 3px 10px;
    border-radius: 100px;
  }

  /* INTERVENTION */
  .intervention {
    max-width: 640px;
    margin: 0 auto;
    padding: 40px 40px 80px;
    position: relative;
    z-index: 1;
  }

  .intervention-back {
    display: flex;
    align-items: center;
    gap: 8px;
    color: var(--text-dim);
    font-size: 13px;
    cursor: pointer;
    margin-bottom: 40px;
    transition: color 0.2s;
    background: none;
    border: none;
    font-family: 'DM Sans', sans-serif;
  }

  .intervention-back:hover { color: var(--amber); }

  .intervention-header {
    margin-bottom: 40px;
  }

  .intervention-header h2 {
    font-family: 'Cormorant Garamond', serif;
    font-size: 42px;
    font-weight: 300;
    margin-bottom: 10px;
  }

  .intervention-header p { color: var(--text-dim); font-size: 15px; line-height: 1.7; }

  /* BREATHING */
  .breath-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 40px 0;
  }

  .breath-circle-wrap {
    position: relative;
    width: 280px;
    height: 280px;
    margin-bottom: 24px;
  }

  .breath-svg-ring {
    width: 100%;
    height: 100%;
    transform: rotate(-90deg);
    position: absolute;
    inset: 0;
  }

  .breath-ring-track {
    fill: none;
    stroke: rgba(255,255,255,0.05);
    stroke-width: 1;
  }

  .breath-ring-arc {
    fill: none;
    stroke: var(--amber);
    stroke-width: 1.5;
    stroke-linecap: butt;
    transition: stroke-dashoffset var(--breath-duration, 4s) linear;
  }

  /* Legacy circle — kept for sigh tool */
  .breath-circle {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    background: transparent;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform var(--breath-duration, 4s) ease-in-out;
  }

  .breath-circle.expand { transform: scale(1.05); }
  .breath-circle.hold   { transform: scale(1.05); }
  .breath-circle.contract { transform: scale(1); }

  @keyframes breathe-ring {
    0%, 100% { opacity: 0.3; transform: scale(1); }
    50% { opacity: 0.08; transform: scale(1.5); }
  }

  .breath-inner {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 4px;
  }

  .breath-count {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 52px;
    font-weight: 300;
    color: var(--amber);
    line-height: 1;
    letter-spacing: -0.02em;
  }

  .breath-phase {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 9px;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--text-muted);
    margin-bottom: 12px;
    text-align: center;
  }

  .breath-instruction {
    font-family: 'Cormorant Garamond', serif;
    font-size: 22px;
    font-style: italic;
    font-weight: 300;
    color: var(--text-dim);
    text-align: center;
    margin-bottom: 8px;
    line-height: 1.3;
    transition: opacity 0.5s ease;
  }

  /* GROUNDING */
  .grounding-steps { display: flex; flex-direction: column; gap: 16px; }

  .ground-step {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 20px 24px;
    transition: all 0.3s;
  }

  .ground-step.active {
    border-color: var(--amber);
    background: var(--amber-glow);
  }

  .ground-step.done {
    border-color: var(--green);
    background: var(--green-glow);
    opacity: 0.7;
  }

  .ground-step-header {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 8px;
  }

  .ground-number {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--amber-glow);
    border: 1px solid var(--amber-dim);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    color: var(--amber);
    flex-shrink: 0;
  }

  .ground-step.done .ground-number {
    background: var(--green-glow);
    border-color: var(--green);
    color: var(--green);
  }

  .ground-label { font-size: 15px; font-weight: 500; }
  .ground-desc { font-size: 13px; color: var(--text-dim); line-height: 1.6; padding-left: 42px; }

  .ground-input {
    width: 100%;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 12px 16px;
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-size: 14px;
    margin-top: 12px;
    margin-left: 42px;
    width: calc(100% - 42px);
    transition: border-color 0.2s;
    resize: none;
  }

  .ground-input:focus { outline: none; border-color: var(--amber); }

  /* REFRAME */
  .reframe-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 32px;
    margin-bottom: 20px;
  }

  .reframe-question {
    font-family: 'Cormorant Garamond', serif;
    font-size: 26px;
    font-weight: 300;
    font-style: italic;
    margin-bottom: 20px;
    line-height: 1.4;
    color: var(--text);
  }

  .reframe-input {
    width: 100%;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 14px 16px;
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-size: 14px;
    line-height: 1.6;
    resize: none;
    min-height: 100px;
    transition: border-color 0.2s;
  }

  .reframe-input:focus { outline: none; border-color: var(--amber); }

  .reframe-insight {
    background: var(--amber-glow);
    border: 1px solid var(--amber-dim);
    border-radius: 10px;
    padding: 20px 24px;
    margin-top: 20px;
  }

  .reframe-insight p {
    font-family: 'Cormorant Garamond', serif;
    font-size: 18px;
    font-style: italic;
    color: var(--amber);
    line-height: 1.6;
  }

  /* AI CONSULT */
  .ai-container {
    display: flex;
    flex-direction: column;
    max-height: 480px;
    min-height: 300px;
  }

  .ai-messages {
    flex: 1;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 16px;
    padding: 4px 0 20px;
    scrollbar-width: thin;
    scrollbar-color: var(--border) transparent;
    -webkit-overflow-scrolling: touch;
  }

  .message {
    /* May 13, 2026 — Reframe UI foundation: chrome reduction. Cards around
       messages stripped (was the wellness-app signature). Vertical rhythm via
       padding + hairline rule replaces container framing. */
    display: block;
    padding: 24px 0;
    border-bottom: 1px solid var(--border-printed);
  }
  .message:last-child { border-bottom: none; }

  .message-avatar {
    /* Hidden as of May 13, 2026 — typography carries voice (Move 4: mono for
       user, serif for AI). CSS retained for potential future use. */
    display: none;
  }

  .message-bubble {
    /* May 13, 2026 — container stripped. Text floats on the page bg. Mode
       color signal moved to AI lead-sentence color (Move 2) and distortion
       label (unchanged). Inline style overrides in JSX also removed. */
    background: transparent;
    border: none;
    border-radius: 0;
    padding: 0;
    max-width: 100%;
    color: var(--text);
  }

  /* REPLY PILL — May 13, 2026, Commit 2 Move 3.
     Collapsed: thin mono pill at bottom of screen. Expanded: slides up into
     the full input row (textarea + paperclip + mic + Send). State driven by
     replyExpanded; auto-collapse on AI response render, auto-expand on fresh
     session (messages.length === 0). */
  .reply-pill {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 44px;
    background: var(--surface);
    border: 1px solid var(--amber-dim);
    border-radius: var(--r-lg);
    color: var(--text-dim);
    font-family: 'IBM Plex Mono', monospace;
    font-size: 12px;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    cursor: pointer;
    transition: border-color var(--motion-quick) var(--ease-prestige), background var(--motion-quick) var(--ease-prestige);
  }
  .reply-pill:hover { border-color: var(--amber); background: var(--surface2); }
  .reply-pill .arrow { margin-left: 8px; color: var(--amber); }

  /* OVERFLOW TRIGGER — top-right of Reframe screen.
     Opens the overflow sheet containing Done for now / Start new / I want a
     different response / Crisis resources / Back. */
  .overflow-trigger {
    background: transparent;
    border: none;
    color: var(--text-dim);
    font-size: 20px;
    cursor: pointer;
    padding: 4px 8px;
    line-height: 1;
    letter-spacing: 0.1em;
    transition: color var(--motion-quick) var(--ease-prestige);
  }
  .overflow-trigger:hover { color: var(--text); }

  /* OVERFLOW SHEET — slides down from top. Listed actions, hairline separated. */
  .overflow-backdrop {
    position: fixed;
    inset: 0;
    z-index: 80;
    background: rgba(0,0,0,0.4);
    animation: overflow-fade-in 240ms var(--ease-prestige);
  }
  .overflow-sheet {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 81;
    background: var(--bg);
    border-bottom: 1px solid var(--border);
    padding: 16px 0 12px;
    animation: overflow-slide-down 280ms var(--ease-prestige);
  }
  .overflow-sheet-row {
    display: block;
    width: 100%;
    text-align: left;
    background: transparent;
    border: none;
    border-top: 1px solid var(--border-printed);
    color: var(--text-dim);
    font-family: 'DM Sans', sans-serif;
    font-size: 15px;
    padding: 14px 24px;
    cursor: pointer;
    transition: background var(--motion-quick) var(--ease-prestige), color var(--motion-quick) var(--ease-prestige);
  }
  .overflow-sheet-row:first-child { border-top: none; }
  .overflow-sheet-row:hover { background: var(--surface2); color: var(--text); }
  @keyframes overflow-fade-in {
    from { opacity: 0; }
    to { opacity: 1; }
  }
  @keyframes overflow-slide-down {
    from { transform: translateY(-100%); }
    to { transform: translateY(0); }
  }

  .message.user .message-bubble {
    background: var(--surface2);
  }

  .ai-input-row {
    display: flex;
    gap: 10px;
    padding-top: 16px;
    border-top: 1px solid var(--border);
    align-items: flex-end;
    position: relative;
  }

  .ai-input {
    flex: 1;
    width: 100%;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 12px 16px;
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-size: 14px;
    transition: border-color 0.2s;
    min-height: 80px;
    max-height: 160px;
    resize: none;
    line-height: 1.5;
  }

  .ai-input:focus { outline: none; border-color: var(--amber); }

  .btn-send {
    padding: 12px 20px;
    background: var(--amber);
    color: #0e0f11;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 500;
    font-size: 13px;
    font-family: 'DM Sans', sans-serif;
    transition: all 0.2s;
  }

  .btn-send:hover { background: var(--amber); filter: brightness(1.15); }
  .btn-send:disabled { opacity: 0.5; cursor: not-allowed; }

  @keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.3; }
  }

  @keyframes entrain60 {
    0%, 100% { opacity: 0.85; }
    50% { opacity: 1; }
  }

  @keyframes entrain60glow {
    0%, 100% { box-shadow: 0 0 0 rgba(201,147,58,0); }
    50% { box-shadow: 0 0 18px rgba(201,147,58,0.08); }
  }

  @keyframes deltaFlash {
    0% { opacity: 0; transform: scale(0.8); }
    40% { opacity: 1; transform: scale(1.08); }
    100% { opacity: 1; transform: scale(1); }
  }

  @keyframes heroReflection {
    0%       { transform: translateX(-150%) skewX(-12deg); }
    18%      { transform: translateX(150%) skewX(-12deg); }
    100%     { transform: translateX(150%) skewX(-12deg); }
  }
  .hero-cta-reflect {
    position: relative;
    overflow: hidden;
    isolation: isolate;
  }
  .hero-cta-reflect::before {
    content: "";
    position: absolute;
    inset: 0;
    z-index: 0;
    pointer-events: none;
    background: linear-gradient(
      100deg,
      transparent 0%,
      transparent 35%,
      color-mix(in srgb, var(--amber) 18%, transparent) 47%,
      color-mix(in srgb, var(--amber) 28%, transparent) 50%,
      color-mix(in srgb, var(--amber) 18%, transparent) 53%,
      transparent 65%,
      transparent 100%
    );
    width: 60%;
    transform: translateX(-150%) skewX(-12deg);
    animation: heroReflection 8s cubic-bezier(0.4, 0, 0.2, 1) infinite;
  }
  .hero-cta-reflect > * { position: relative; z-index: 1; }
  .reduced-motion .hero-cta-reflect::before { animation: none !important; opacity: 0; }

  @keyframes deltaGlow {
    0% { text-shadow: 0 0 0 rgba(201,147,58,0); }
    50% { text-shadow: 0 0 28px rgba(201,147,58,0.5); }
    100% { text-shadow: 0 0 12px rgba(201,147,58,0.2); }
  }

  @keyframes uatBannerFlash {
    0%, 100% {
      box-shadow: inset 0 1px 0 rgba(255,255,255,0.03), 0 0 0 rgba(201,147,58,0);
      border-color: var(--amber-dim);
    }
    50% {
      box-shadow: inset 0 1px 0 rgba(255,255,255,0.03), 0 0 18px rgba(201,147,58,0.18);
      border-color: var(--amber);
    }
  }

  /* BODY SCAN */
  .scan-body {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  .scan-area {
    background: var(--surface);
    border: 0.5px solid var(--border);
    border-radius: var(--r);
    padding: 12px 16px;
    transition: all 0.25s ease-out;
    cursor: pointer;
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.025);
  }

  .scan-area.active {
    border-color: var(--amber);
    background: var(--amber-glow);
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.03), 0 0 0 1px var(--amber-dim);
  }

  .scan-area.done {
    border-color: var(--amber-dim);
    opacity: 0.45;
  }

  .scan-area-name {
    font-family: 'DM Sans', sans-serif;
    font-size: 14px;
    font-weight: 400;
    color: var(--text-dim);
    transition: color 0.25s;
    margin-bottom: 3px;
  }

  .scan-area.active .scan-area-name {
    color: var(--amber);
    font-weight: 500;
  }

  .scan-area.done .scan-area-name {
    color: var(--text-muted);
  }

  .scan-area-prompt {
    font-size: 12px;
    color: var(--text-muted);
    line-height: 1.5;
  }

  .tension-bar {
    display: flex;
    gap: 4px;
    margin-top: 12px;
  }

  .tension-dot {
    flex: 1;
    height: 4px;
    border-radius: 2px;
    background: var(--border);
    cursor: pointer;
    transition: background 0.2s;
  }

  .tension-dot.active { background: var(--amber); }

  /* PROGRESS / COMPLETE */
  .complete {
    text-align: center;
    padding: 48px 20px;
  }

  .complete-icon {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    background: var(--amber-glow);
    border: 0.5px solid var(--amber);
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'IBM Plex Mono', monospace;
    font-size: 20px;
    color: var(--amber);
    margin: 0 auto 28px;
    box-shadow: 0 0 24px rgba(200,146,42,0.08);
  }

  .complete h2 {
    font-family: 'Cormorant Garamond', serif;
    font-size: 42px;
    font-weight: 300;
    margin-bottom: 8px;
  }

  .complete p {
    color: var(--text-dim);
    font-size: 14px;
    line-height: 1.7;
    max-width: 400px;
    margin: 0 auto 8px;
  }

  .complete-data {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 10px;
    letter-spacing: 0.15em;
    text-transform: uppercase;
    color: var(--text-muted);
    margin-bottom: 28px;
  }

  /* PRICING */
  .pricing {
    max-width: 800px;
    margin: 0 auto;
    padding: 60px 40px 80px;
    position: relative;
    z-index: 1;
  }

  .pricing-header {
    text-align: center;
    margin-bottom: 48px;
  }

  .pricing-header h2 {
    font-family: 'Cormorant Garamond', serif;
    font-size: 42px;
    font-weight: 300;
    margin-bottom: 10px;
  }

  .pricing-header p { color: var(--text-dim); font-size: 15px; }

  .pricing-cards {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
  }

  @media (max-width: 560px) { .pricing-cards { grid-template-columns: 1fr; } }

  .pricing-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 32px;
    position: relative;
  }

  .pricing-card.featured {
    border-color: var(--amber);
    background: linear-gradient(160deg, rgba(201,147,58,0.06) 0%, var(--surface) 100%);
  }

  .pricing-badge {
    position: absolute;
    top: -12px;
    left: 50%;
    transform: translateX(-50%);
    background: var(--amber);
    color: #0e0f11;
    font-size: 11px;
    font-weight: 500;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    padding: 4px 14px;
    border-radius: 100px;
  }

  .pricing-period { font-size: 12px; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.1em; margin-bottom: 8px; }

  .pricing-price {
    font-family: 'Cormorant Garamond', serif;
    font-size: 52px;
    font-weight: 300;
    color: var(--text);
    line-height: 1;
    margin-bottom: 4px;
  }

  .pricing-price sup { font-size: 22px; vertical-align: super; }

  .pricing-save { font-size: 12px; color: var(--amber); margin-bottom: 28px; }

  .pricing-features { list-style: none; margin-bottom: 28px; }

  .pricing-features li {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 13px;
    color: var(--text-dim);
    padding: 6px 0;
    border-bottom: 1px solid var(--border);
  }

  .pricing-features li:last-child { border-bottom: none; }
  .pricing-features li::before { content: '—'; color: var(--amber); font-size: 11px; }

  /* PRIVACY */
  .privacy {
    max-width: 700px;
    margin: 0 auto;
    padding: 60px 40px 80px;
    position: relative;
    z-index: 1;
  }

  .privacy h1 {
    font-family: 'Cormorant Garamond', serif;
    font-size: 42px;
    font-weight: 300;
    margin-bottom: 8px;
  }

  .privacy-date { color: var(--text-dim); font-size: 13px; margin-bottom: 40px; }

  .privacy h2 {
    font-size: 16px;
    font-weight: 500;
    margin: 32px 0 12px;
    color: var(--amber);
  }

  .privacy p { font-size: 14px; color: var(--text-dim); line-height: 1.8; margin-bottom: 16px; }

  /* FOOTER */
  .footer {
    border-top: 1px solid var(--border);
    padding: 32px 40px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: gap;
    position: relative;
    z-index: 1;
  }

  .footer-logo {
    font-family: 'Cormorant Garamond', serif;
    font-size: 18px;
    font-weight: 300;
    letter-spacing: 0.1em;
    color: var(--text-dim);
  }

  .footer-links {
    display: flex;
    gap: 24px;
  }

  .footer-links button {
    background: none;
    border: none;
    color: var(--text-dim);
    font-family: 'DM Sans', sans-serif;
    font-size: 12px;
    cursor: pointer;
    transition: color 0.2s;
    letter-spacing: 0.06em;
  }

  .footer-links button:hover { color: var(--amber); }

  .footer-copy { color: var(--text-dim); font-size: 12px; }

  /* DISCLAIMER */
  .disclaimer {
    background: var(--surface);
    border: 1px solid var(--border);
    border-left: 3px solid var(--amber-dim);
    border-radius: 6px;
    padding: 12px 16px;
    font-size: 12px;
    color: var(--text-dim);
    line-height: 1.6;
    margin-bottom: 16px;
  }

  @media (max-width: 640px) {
    .nav { padding: 20px 24px; }
    .home { padding: 40px 24px; }
    .tools { padding: 32px 24px 60px; }
    .intervention { padding: 32px 28px 60px; }
    .pricing { padding: 40px 24px 60px; }
    .privacy { padding: 40px 24px 60px; }
    .footer { padding: 24px; flex-direction: column; gap: 16px; text-align: center; }
    .footer-links { flex-wrap: wrap; justify-content: center; }
    .home-title { font-size: 42px; }
  }

  /* PANIC BUTTON */
  .panic-btn {
    width: 180px;
    height: 180px;
    border-radius: 50%;
    background: radial-gradient(circle at 40% 35%, #1e1408, #0e0a04);
    border: 2px solid var(--amber-dim);
    color: var(--amber);
    font-family: 'Cormorant Garamond', serif;
    font-size: 18px;
    font-weight: 400;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    line-height: 1.4;
    padding: 24px;
    margin-bottom: 16px;
    box-shadow: 0 0 40px rgba(201,147,58,0.08), inset 0 0 30px rgba(201,147,58,0.04);
    transition: all 0.3s ease;
    -webkit-tap-highlight-color: transparent;
  }

  .panic-btn:hover {
    box-shadow: 0 0 60px rgba(201,147,58,0.15), inset 0 0 40px rgba(201,147,58,0.06);
    border-color: var(--amber);
    transform: scale(1.03);
  }

  .panic-btn:active {
    transform: scale(0.97);
  }

  .panic-btn-text {
    letter-spacing: 0.04em;
  }

  /* PANIC MODE */
  .panic-screen {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: calc(100vh - 73px);
    padding: 40px 24px;
    text-align: center;
    position: relative;
    z-index: 1;
  }

  .panic-instruction {
    font-size: 15px;
    font-style: italic;
    color: var(--text-dim);
    letter-spacing: 0.06em;
    margin-bottom: 48px;
    opacity: 0;
    animation: panicFadeIn 1.5s ease 0.5s forwards;
  }

  @keyframes panicFadeIn {
    from { opacity: 0; transform: translateY(8px); }
    to { opacity: 1; transform: translateY(0); }
  }

  .panic-circle-wrap {
    width: 220px;
    height: 220px;
    margin-bottom: 48px;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .panic-circle {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(201,147,58,0.10) 0%, rgba(201,147,58,0.02) 60%, transparent 100%);
    border: 1px solid var(--amber-dim);
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.8s ease-in-out, box-shadow 0.8s ease-in-out;
  }

  .panic-phase {
    font-family: 'Cormorant Garamond', serif;
    font-size: 20px;
    font-weight: 300;
    color: var(--amber);
    letter-spacing: 0.08em;
  }

  .panic-counter {
    font-size: 12px;
    color: var(--text-muted);
    letter-spacing: 0.1em;
  }

  .panic-done {
    animation: panicFadeIn 0.8s ease forwards;
  }

  .panic-done-text {
    font-family: 'Cormorant Garamond', serif;
    font-size: 18px;
    font-weight: 300;
    font-style: italic;
    color: var(--text-dim);
    max-width: 280px;
    line-height: 1.6;
    margin-bottom: 32px;
  }

  /* Screen-light mode overlay */
  .screenlight-overlay {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(0, 0, 0, 0.92);
    z-index: 50;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
  }
  .screenlight-overlay * { pointer-events: auto; }
  .screenlight-active .breath-circle { opacity: 0.3; }
  .screenlight-active .panic-phase { font-size: 24px; }
  .screenlight-active .panic-counter { opacity: 0.2; }

  /* Reduced motion */
  .reduced-motion .breath-circle { transition: none !important; animation: none !important; }
  .reduced-motion .scan-area { transition: none !important; }
`;

