const applyThemePreset = (themeId, highContrast = false) => {
  if (typeof document === "undefined") return;
  const preset = THEME_PRESETS[themeId] || THEME_PRESETS.dark;
  const root = document.documentElement;
  Object.entries(preset).forEach(([token, value]) => root.style.setProperty(token, value));
  if (highContrast) {
    const overlay = themeId === "light" ? HIGH_CONTRAST_OVERLAY_LIGHT : HIGH_CONTRAST_OVERLAY;
    Object.entries(overlay).forEach(([token, value]) => root.style.setProperty(token, value));
  }
};

const readArrayFromStorage = (key) => {
  try {
    const parsed = JSON.parse(localStorage.getItem(key) || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

// READ + WRITE PATH (audit philosophy v1.3 Layer 2.39, Path A migration May 8 2026):
// stillform_sessions is in SECURE_KEYS. Writes encrypt via secureWrite;
// reads return decrypted SecureCache values via secureRead. The async
// variants (getSessionsFromStorageAsync at line ~4372) already use the
// encrypted readJSON/writeJSON path — sync and async are now consistent.
//
// Existing-user migration: primeSecureCache (line ~8954) detects plaintext
// at boot, primes SecureCache from it, fires off background re-encryption.
// No data loss across the migration boundary.
const getSessionsFromStorage = () => secureRead(SESSION_STORAGE_KEY, []);

const setSessionsInStorage = (sessions) => {
  try {
    secureWrite(SESSION_STORAGE_KEY, Array.isArray(sessions) ? sessions : []);
  } catch {}
};

const appendSessionToStorage = (entry) => {
  if (!entry) return getSessionCountFromStorage();
  // Auto-attach bioFilter snapshot if caller didn't set it. Closes the
  // Stage 5 instrumentation gap ("high-load sessions" + "high-load delta")
  // without requiring all 8 session-write sites to remember the field.
  if (entry.bioFilter === undefined) {
    try {
      const bf = getActiveBioFilter();
      if (bf) entry.bioFilter = bf;
    } catch {}
  }

  // Gap 11 (May 12, 2026) — capture pre-session marker met-state across
  // all five stages so post-session compute can detect flips. computeStageMarkers
  // and STAGE_REPS are defined later in module source order but resolved at
  // call time (this is a const-defined function whose body runs at invocation,
  // not definition). All module-level consts have evaluated by then.
  let preStates = null;
  try {
    if (typeof computeStageMarkers === "function") {
      preStates = {};
      for (let sid = 1; sid <= 5; sid++) {
        computeStageMarkers(sid).forEach(m => {
          if (m.status === "shipped") preStates[m.id] = m.met;
        });
      }
    }
  } catch {}

  const sessions = getSessionsFromStorage();
  sessions.push(entry);
  setSessionsInStorage(sessions);

  // Gap 11 — recompute marker met-state. If any shipped marker flipped from
  // false to true, write stillform_last_rep_counted for the next home render
  // to surface as a capacity-rep-counted banner. Only the FIRST flipped marker
  // per session is surfaced (one rep per session keeps the feedback discrete).
  try {
    if (preStates && typeof computeStageMarkers === "function" && typeof STAGE_DEFINITIONS !== "undefined") {
      let surfaced = false;
      for (let sid = 1; sid <= 5 && !surfaced; sid++) {
        const markers = computeStageMarkers(sid);
        const stage = STAGE_DEFINITIONS[sid];
        for (const m of markers) {
          if (m.status !== "shipped") continue;
          if (preStates[m.id] === false && m.met === true) {
            const repEntry = (typeof STAGE_REPS !== "undefined") ? STAGE_REPS[m.id] : null;
            const payload = {
              markerId: m.id,
              markerLabel: m.label,
              stageId: sid,
              stageName: stage.name,
              repStatement: repEntry ? repEntry.statement : null,
              timestamp: new Date().toISOString(),
            };
            try { localStorage.setItem("stillform_last_rep_counted", JSON.stringify(payload)); } catch {}
            try { window.plausible?.("Capacity Rep Counted", { props: { marker: m.id, stage: stage.name } }); } catch {}
            surfaced = true;
            break;
          }
        }
      }
    }
  } catch {}

  return sessions.length;
};

// Compute the current consecutive-day session streak. Looks back from today
// using stillformDay (morning_start-aware) so a 5am session counts toward the
// previous day for late-night practitioners. Returns 0 if today and yesterday
// have no sessions.
const computeStreak = () => {
  try {
    const sessions = getSessionsFromStorage();
    const daySet = new Set(sessions.map(s => TimeKeeper.stillformDayOf(s.timestamp)).filter(Boolean));
    let streak = 0;
    for (let i = 0; i < 365; i++) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      if (daySet.has(TimeKeeper.stillformDayOf(d))) streak++;
      else break;
    }
    return streak;
  } catch { return 0; }
};

// Count today's sessions for the home-screen daily-rep counter. Uses
// stillformDay so the count rolls over at the user's morning_start, not midnight.
const countTodaysSessions = () => {
  try {
    const today = TimeKeeper.stillformDay();
    return getSessionsFromStorage().filter(s => TimeKeeper.stillformDayOf(s.timestamp) === today).length;
  } catch { return 0; }
};

// Get the most recent session (any tool) within the last 24h. Used for the
// "pick up where you left off" affordance on home. Returns null if no recent
// session.
const getMostRecentSession = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (!sessions.length) return null;
    const last = sessions[sessions.length - 1];
    if (!last?.timestamp) return null;
    const ageMs = Date.now() - new Date(last.timestamp).getTime();
    if (ageMs > 24 * 60 * 60 * 1000) return null; // >24h, not relevant
    return { ...last, ageMs };
  } catch { return null; }
};

// Format an age in ms as a brief human label: "12m ago", "2h ago", "yesterday".
const formatSessionAge = (ageMs) => {
  if (ageMs < 60 * 1000) return "just now";
  if (ageMs < 60 * 60 * 1000) return `${Math.floor(ageMs / (60 * 1000))}m ago`;
  if (ageMs < 24 * 60 * 60 * 1000) return `${Math.floor(ageMs / (60 * 60 * 1000))}h ago`;
  return "yesterday";
};

// Map session.tools array to a readable tool label for the resume affordance.
const labelForLastSession = (session) => {
  const tools = Array.isArray(session?.tools) ? session.tools : [];
  if (tools.includes("reframe")) return "Reframe";
  if (tools.includes("body-scan")) return "Body Scan";
  if (tools.includes("breathe") && tools.includes("ground")) return "Breathe + Ground";
  if (tools.includes("breathe")) return "Breathe";
  if (tools.includes("metacognition")) return "Self Mode";
  return "Last session";
};

// ─── COGNITIVE FUNCTION MEASUREMENT — Phase 0 storage infrastructure ────
// Per COGNITIVE_FUNCTION_MEASUREMENT_SPEC.md (Apr 30, 2026). This is the
// data layer only — no UI, no stimulus libraries, no surfacing logic.
// Stimulus libraries, exercise UI, and surfacing logic ship in subsequent
// phases per the spec.
//
// Storage shape: an array of function-check records. Each record:
//   {
//     v: 1,                          // schema version
//     id: "fc_<timestamp>",          // unique
//     candidate: "affect-labeling" | "interoceptive-latency" | "cognitive-defusion",
//     timestamp: ISO8601,
//     primaryMs: number,             // latency in ms (Candidate 1, 2)
//     primaryCount: number,          // count of frames (Candidate 3)
//     specificity: 0 | 0.5 | 1,      // for Candidate 2
//     bioFilter: string[]|null,      // user state at measurement time
//     toolsBeforeMs: { breathe, body-scan, reframe } | null,
//                                    // recent practice context
//   }
//
// Honest framing rules from spec §"What it can't do" enforced at surfacing
// time, not at storage time. Storage is dumb; comparison logic is where
// the integrity claim lives.
// ─── PATTERN DISRUPTION LAYER — May 7, 2026 ───────────────────────────
// Per PATTERN_DISRUPTION_SPEC.md. Detects repeated loops across the user's
// recent sessions (≥3 instances of the same signal across 8 dimensions),
// surfaces the pattern with an offered disruptor, tracks dismissals
// (two-strikes-and-drop), and records disruptor sessions.
//
// Storage:
//   stillform_pattern_detections: array of detected pattern instances
//   stillform_disruptor_sessions: array of disruptor tool runs
//
// Detection runs deterministically (no AI cost) on a recent-session window.
// AI-aware enrichment (reasoning + dimension classification) layered on top
// when a pre-filter threshold trips. Per spec §4 open question Q4: AI runs
// only after deterministic pre-filter, not on every data point.

const PATTERN_DETECTIONS_KEY = "stillform_pattern_detections";
const DISRUPTOR_SESSIONS_KEY = "stillform_disruptor_sessions";

// Detection threshold: 3 data points of the same signal in the recent window.
// Window: last 14 days OR last 10 sessions, whichever is shorter.
const PATTERN_THRESHOLD = 3;
const PATTERN_WINDOW_DAYS = 14;
const PATTERN_WINDOW_SESSIONS = 10;

// Maximum stored detections — older ones are pruned to keep storage bounded.
const PATTERN_DETECTIONS_MAX = 50;
const DISRUPTOR_SESSIONS_MAX = 100;

// Eight loop-signal dimensions per spec §2.2. Each is one axis the
// detector can register repetition on. Body-first detection (chips +
// bio-filter) is explicit per spec §2.3.
const PATTERN_DIMENSIONS = Object.freeze({
  SAME_CHIP: "same_chip",            // post-state chip repeats
  SAME_BIO_FILTER: "same_bio_filter", // hardware state repeats
  SAME_FEELSTATE: "same_feelstate",  // entry feel state repeats
  SAME_TENSION_AREA: "same_tension_area", // body scan area repeats
  SAME_DISTORTION: "same_distortion", // bias profile distortion repeats
  SAME_TOOL_PATH: "same_tool_path",  // tool sequence repeats
  SHIFT_NOT_LANDING: "shift_not_landing", // post-rate stays equal/lower
  SAME_REFRAME_CONTEXT: "same_reframe_context" // entryMode + feelState combo
});

const getPatternDetectionsFromStorage = () => {
  try {
    const raw = secureRead(PATTERN_DETECTIONS_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

const writePatternDetections = (detections) => {
  try {
    const trimmed = (Array.isArray(detections) ? detections : []).slice(-PATTERN_DETECTIONS_MAX);
    secureWrite(PATTERN_DETECTIONS_KEY, trimmed);
    return true;
  } catch { return false; }
};

const getDisruptorSessionsFromStorage = () => {
  try {
    const raw = secureRead(DISRUPTOR_SESSIONS_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

const appendDisruptorSession = (entry) => {
  if (!entry) return null;
  const record = {
    id: entry.id || `ds_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    timestamp: entry.timestamp || new Date().toISOString(),
    patternId: entry.patternId || null,
    dimension: entry.dimension || null,
    durationMs: typeof entry.durationMs === "number" ? entry.durationMs : null,
    completed: entry.completed === true,
    pathway: entry.pathway || "somatic-redirection"
  };
  try {
    const existing = getDisruptorSessionsFromStorage();
    const next = [...existing, record].slice(-DISRUPTOR_SESSIONS_MAX);
    secureWrite(DISRUPTOR_SESSIONS_KEY, next);
    return record;
  } catch { return null; }
};

// Deterministic pre-filter — counts repeats across the 8 dimensions in the
// recent window. Returns array of detected patterns, each with:
//   { dimension, value, count, dataPoints: [session refs] }
// Cheap to run (pure JS over already-loaded session history). AI enrichment
// happens only after this pre-filter trips.
const detectPatternsDeterministic = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (sessions.length < PATTERN_THRESHOLD) return [];

    // Window: most recent N sessions OR last D days, whichever is shorter.
    const windowStart = TimeKeeper.daysAgoMs(PATTERN_WINDOW_DAYS);
    const recent = sessions
      .filter(s => {
        const t = new Date(s.timestamp || 0).getTime();
        return !Number.isNaN(t) && t >= windowStart;
      })
      .slice(-PATTERN_WINDOW_SESSIONS);

    if (recent.length < PATTERN_THRESHOLD) return [];

    // Count repeats per dimension.
    const buckets = {
      [PATTERN_DIMENSIONS.SAME_CHIP]: new Map(),
      [PATTERN_DIMENSIONS.SAME_BIO_FILTER]: new Map(),
      [PATTERN_DIMENSIONS.SAME_FEELSTATE]: new Map(),
      [PATTERN_DIMENSIONS.SAME_TENSION_AREA]: new Map(),
      [PATTERN_DIMENSIONS.SAME_TOOL_PATH]: new Map(),
      [PATTERN_DIMENSIONS.SHIFT_NOT_LANDING]: new Map()
    };

    const recordHit = (dimension, value, sessionRef) => {
      if (!value) return;
      const bucket = buckets[dimension];
      if (!bucket) return;
      const existing = bucket.get(value) || { value, count: 0, dataPoints: [] };
      existing.count += 1;
      existing.dataPoints.push(sessionRef);
      bucket.set(value, existing);
    };

    for (const s of recent) {
      const ref = { timestamp: s.timestamp, sessionId: s.id || null };
      // Same post-state chip
      if (s.postState) recordHit(PATTERN_DIMENSIONS.SAME_CHIP, s.postState, ref);
      // Same bio-filter
      if (s.bioFilter) {
        const tokens = String(s.bioFilter).split(",").map(t => t.trim()).filter(Boolean);
        for (const t of tokens) recordHit(PATTERN_DIMENSIONS.SAME_BIO_FILTER, t, ref);
      }
      // Same entry feel state
      if (s.preState) recordHit(PATTERN_DIMENSIONS.SAME_FEELSTATE, s.preState, ref);
      // Same tool sequence
      if (Array.isArray(s.tools) && s.tools.length > 0) {
        recordHit(PATTERN_DIMENSIONS.SAME_TOOL_PATH, s.tools.join("→"), ref);
      }
      // Body scan tension areas
      if (s.bodyScanTension && typeof s.bodyScanTension === "object") {
        for (const [area, level] of Object.entries(s.bodyScanTension)) {
          if (typeof level === "number" && level >= 3) {
            recordHit(PATTERN_DIMENSIONS.SAME_TENSION_AREA, area, { ...ref, level });
          }
        }
      }
      // Shift not landing — post rate <= pre rate
      if (typeof s.preRate === "number" && typeof s.postRate === "number" && s.postRate <= s.preRate) {
        recordHit(PATTERN_DIMENSIONS.SHIFT_NOT_LANDING, "post_le_pre", ref);
      }
    }

    // Collect any bucket entries that hit threshold.
    const detected = [];
    for (const [dimension, bucket] of Object.entries(buckets)) {
      for (const entry of bucket.values()) {
        if (entry.count >= PATTERN_THRESHOLD) {
          detected.push({
            dimension,
            value: entry.value,
            count: entry.count,
            dataPoints: entry.dataPoints
          });
        }
      }
    }
    // Strongest patterns first.
    detected.sort((a, b) => b.count - a.count);
    return detected;
  } catch { return []; }
};

// Surface state for a pattern detection record. State machine per spec §3.2:
//   "active" → user has not yet responded
//   "dismissed_once" → user dismissed once; will re-fire on next session/day
//   "accepted" → user accepted, routed into disruptor
//   "closed" → two strikes (dismissed twice), pattern instance closed
const PATTERN_STATES = Object.freeze({
  ACTIVE: "active",
  DISMISSED_ONCE: "dismissed_once",
  ACCEPTED: "accepted",
  CLOSED: "closed"
});

// Plain-language label for a pattern dimension — used in the prompt + the
// transparency surface.
const PATTERN_DIMENSION_LABELS = {
  [PATTERN_DIMENSIONS.SAME_CHIP]: "Same closing state",
  [PATTERN_DIMENSIONS.SAME_BIO_FILTER]: "Same hardware state",
  [PATTERN_DIMENSIONS.SAME_FEELSTATE]: "Same entry state",
  [PATTERN_DIMENSIONS.SAME_TENSION_AREA]: "Tension in the same place",
  [PATTERN_DIMENSIONS.SAME_TOOL_PATH]: "Same tool sequence",
  [PATTERN_DIMENSIONS.SHIFT_NOT_LANDING]: "Sessions not landing a shift",
  [PATTERN_DIMENSIONS.SAME_DISTORTION]: "Same thinking distortion",
  [PATTERN_DIMENSIONS.SAME_REFRAME_CONTEXT]: "Same Reframe context"
};

// Find or create an active pattern detection record for a given dimension/value
// pair. If a record exists in CLOSED state, do NOT re-open — fresh accrual of
// 3 new data points opens a new instance per spec §3.2 ("two-strikes-and-drop").
// Returns the upserted record.
const upsertPatternDetection = (detection) => {
  if (!detection || !detection.dimension || !detection.value) return null;
  try {
    const existing = getPatternDetectionsFromStorage();
    // Look for an open instance (not CLOSED) matching dimension + value.
    const openIdx = existing.findIndex(d =>
      d.dimension === detection.dimension &&
      d.value === detection.value &&
      d.state !== PATTERN_STATES.CLOSED
    );
    if (openIdx >= 0) {
      // Update count + dataPoints; preserve state machine + history.
      const updated = {
        ...existing[openIdx],
        count: detection.count,
        dataPoints: detection.dataPoints,
        lastSeenAt: new Date().toISOString()
      };
      const next = [...existing];
      next[openIdx] = updated;
      writePatternDetections(next);
      return updated;
    }
    // New instance.
    const record = {
      id: `pd_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      dimension: detection.dimension,
      value: detection.value,
      count: detection.count,
      dataPoints: detection.dataPoints,
      state: PATTERN_STATES.ACTIVE,
      surfacedAt: null,
      dismissedAt: [],
      acceptedAt: null,
      createdAt: new Date().toISOString(),
      lastSeenAt: new Date().toISOString()
    };
    writePatternDetections([...existing, record]);
    return record;
  } catch { return null; }
};

const markPatternSurfaced = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = { ...existing[idx], surfacedAt: existing[idx].surfacedAt || new Date().toISOString() };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

const markPatternDismissed = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const record = existing[idx];
    const dismissedAt = [...(record.dismissedAt || []), new Date().toISOString()];
    // Two strikes → close the pattern instance per spec §3.2.
    const newState = dismissedAt.length >= 2
      ? PATTERN_STATES.CLOSED
      : PATTERN_STATES.DISMISSED_ONCE;
    const updated = { ...record, dismissedAt, state: newState };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

const markPatternAccepted = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = { ...existing[idx], acceptedAt: new Date().toISOString(), state: PATTERN_STATES.ACCEPTED };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

// Returns an active or dismissed-once pattern detection ready to surface.
// Used by the in-app prompt to decide whether to render. Honors the
// re-fire window per spec §3.2 (Q2): if dismissed_once, re-fire on next
// app open same/next day. Beyond that, drop until next surface attempt.
const getActivePatternForSurfacing = () => {
  try {
    const detections = getPatternDetectionsFromStorage();
    // Active first (never surfaced or recently surfaced), then dismissed_once
    // that's eligible for re-fire.
    const active = detections.filter(d => d.state === PATTERN_STATES.ACTIVE);
    if (active.length > 0) {
      // Strongest count first.
      return [...active].sort((a, b) => (b.count || 0) - (a.count || 0))[0];
    }
    const eligibleRefire = detections.filter(d => {
      if (d.state !== PATTERN_STATES.DISMISSED_ONCE) return false;
      const lastDismiss = d.dismissedAt && d.dismissedAt.length > 0
        ? d.dismissedAt[d.dismissedAt.length - 1]
        : null;
      if (!lastDismiss) return false;
      const lastDismissTime = new Date(lastDismiss).getTime();
      if (Number.isNaN(lastDismissTime)) return false;
      // Re-fire allowed if dismissed within the last 48 hours and at least
      // one app open since (caller is the open path itself, so by virtue
      // of being called we're "since dismissal").
      return (Date.now() - lastDismissTime) < (48 * 60 * 60 * 1000);
    });
    if (eligibleRefire.length > 0) {
      return [...eligibleRefire].sort((a, b) => (b.count || 0) - (a.count || 0))[0];
    }
    return null;
  } catch { return null; }
};

// Convenience: run detection + persist any new patterns. Returns the array
// of upserted records so callers can immediately decide whether to surface.
const runPatternDetection = () => {
  try {
    const detected = detectPatternsDeterministic();
    return detected.map(d => upsertPatternDetection(d)).filter(Boolean);
  } catch { return []; }
};

// ─── PATTERN ENRICHMENT (AI-AWARE LAYER) ──────────────────────────────
// Per PATTERN_DISRUPTION_SPEC.md §4 Q4 — AI runs after deterministic
// pre-filter, not on every data point. Enrichment turns the count-based
// signal into observation-mode reasoning ("the closing state isn't moving
// with the practice" instead of "stuck × 3"). Cached on the pattern record
// so re-fires get the cached version without a second AI call.
//
// Always tolerant of failure: server returns heuristic fallback on any AI
// error, and even if the whole call fails, the modal still surfaces with
// count-based copy. AI-down backup case stays working.

const PATTERN_ENRICHMENT_URL = "/.netlify/functions/pattern-enrichment";

// Build the session excerpt context the AI gets. Keeps payload small —
// 6 most recent sessions, only the fields that matter for loop reasoning.
const buildPatternEnrichmentContext = (pattern) => {
  try {
    const sessions = getSessionsFromStorage().slice(-6);
    const sessionExcerpts = sessions.map(s => ({
      timestamp: s.timestamp,
      preState: s.preState || null,
      postState: s.postState || null,
      preRate: typeof s.preRate === "number" ? s.preRate : null,
      postRate: typeof s.postRate === "number" ? s.postRate : null,
      tools: Array.isArray(s.tools) ? s.tools.slice(0, 5) : [],
      bioFilter: s.bioFilter || null
    }));
    let signalProfile = null;
    let biasProfile = null;
    let bioFilter = null;
    // Layer 2.37 source-of-truth: stillform_signal_profile and stillform_bias_profile
    // are in SECURE_KEYS (line ~8855). After encryption migration the raw localStorage
    // value is the encrypted envelope { __enc: true, ... }, NOT the profile data.
    // Reading raw produced silent garbage being sent to the AI pattern enrichment call.
    // Fixed v1.3 to use secureRead which returns the decrypted value from SecureCache.
    try { signalProfile = secureRead("stillform_signal_profile", null); } catch {}
    try { biasProfile = secureRead("stillform_bias_profile", null); } catch {}
    try { bioFilter = getActiveBioFilter ? getActiveBioFilter() : null; } catch {}
    return {
      dimension: pattern.dimension,
      dimensionLabel: PATTERN_DIMENSION_LABELS[pattern.dimension] || pattern.dimension,
      value: pattern.value,
      count: pattern.count,
      dataPoints: pattern.dataPoints || [],
      sessionExcerpts,
      bioFilter,
      signalProfile,
      biasProfile
    };
  } catch {
    // On any error building context, return a minimal payload — the
    // server-side heuristic fallback handles missing fields gracefully.
    return {
      dimension: pattern.dimension,
      dimensionLabel: PATTERN_DIMENSION_LABELS[pattern.dimension] || pattern.dimension,
      value: pattern.value,
      count: pattern.count
    };
  }
};

// Fire-and-forget enrichment call. Returns a promise that resolves to the
// reasoning string (or null on failure). Caller uses this to update the
// pattern record + surfaced state.
const enrichPatternWithAI = async (pattern) => {
  if (!pattern || !pattern.id) return null;
  try {
    const payload = buildPatternEnrichmentContext(pattern);
    const response = await fetch(PATTERN_ENRICHMENT_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) return null;
    const data = await response.json();
    if (typeof data?.reasoning !== "string" || data.reasoning.length === 0) return null;
    return {
      reasoning: data.reasoning,
      confidence: typeof data.confidence === "number" ? data.confidence : null,
      fallback: data.fallback || null,
      enrichedAt: new Date().toISOString()
    };
  } catch { return null; }
};

// Persist enrichment result on the pattern detection record. Idempotent —
// re-running enrichment for the same pattern overwrites prior reasoning.
const updatePatternReasoning = (id, enrichment) => {
  if (!id || !enrichment) return null;
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = {
      ...existing[idx],
      aiReasoning: enrichment.reasoning,
      aiConfidence: enrichment.confidence,
      aiFallback: enrichment.fallback,
      aiEnrichedAt: enrichment.enrichedAt
    };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

// ─── BODY SCAN TENSION DATA HELPERS — Phase 0 for My Progress redesign ────
// Per master todo Surface refinements line 145 ("Body Scan tension data →
// My Progress surface"). These read-only helpers normalize the two tension
// data sources (morning check-in + post-Body-Scan session record) into
// shapes that the My Progress redesign can consume directly.
//
// Storage shapes (already shipped, just being surfaced here):
//   stillform_checkin_history: [{ timestamp, energy, bio, tension: { areaName: 1-5 } }]
//   stillform_sessions: [{ timestamp, tools: [...], bodyScanTension: { areaName: 1-5 } | null }]
//
// Area name canonical values (from Body Scan areas array, line ~4939):
//   "Jaw & Face", "Shoulders & Neck", "Chest & Breath", "Hands & Arms",
//   "Gut & Core", "Legs & Feet"
//
// Morning check-in uses lowercase area keys in some user paths; helpers
// normalize to lowercase for matching across sources. Display surface
// can re-cap.
const BODY_SCAN_AREAS = Object.freeze([
  "Jaw & Face", "Shoulders & Neck", "Chest & Breath",
  "Hands & Arms", "Gut & Core", "Legs & Feet"
]);

const normalizeAreaKey = (k) => String(k || "").trim().toLowerCase();

// Get all morning check-in records that have tension data, sorted oldest-first.
// Returns [] if none. Each record: { date, tension: { areaName: 1-5 } }.
// Get all morning check-ins that captured tension data, sorted oldest-first.
// Returns [] if none. Each record: { timestamp, date, energy, tension: { areaName: 1-5 } }.
//
// READ PATH (audit philosophy v1.3 Layer 2.39 Path A migration, May 8 2026):
// stillform_checkin_history is in SECURE_KEYS and now actually encrypted at rest.
// Writes flow through trackMorningComplete → appendDailyLoopHistory's secure
// branch → secureWrite. Reads via secureRead return the decrypted array primed
// at boot. Same architecture for getBodyScanTensionHistory below.
const getMorningTensionHistory = () => {
  try {
    const raw = secureRead("stillform_checkin_history", []);
    if (!Array.isArray(raw)) return [];
    return raw
      .filter(c => c?.tension && Object.keys(c.tension).length > 0)
      .map(c => ({
        timestamp: c.timestamp || c.date || null,
        date: c.date || (c.timestamp ? c.timestamp.slice(0, 10) : null),
        energy: c.energy || null,
        tension: c.tension
      }))
      .sort((a, b) => {
        const at = new Date(a.timestamp || a.date || 0).getTime();
        const bt = new Date(b.timestamp || b.date || 0).getTime();
        return at - bt;
      });
  } catch { return []; }
};

// Get all body scan sessions that captured post-practice tension, oldest-first.
// Returns [] if none. Each record: { timestamp, bodyScanTension: { areaName: 1-5 } }.
// Excludes low-demand sessions where tension input was skipped (tensionDataCaptured: false).
//
// READ PATH (audit philosophy v1.3 Layer 2.39 Path A migration, May 8 2026):
// stillform_sessions is in SECURE_KEYS and now actually encrypted at rest.
// Writes flow through setSessionsInStorage → secureWrite. Reads via
// getSessionsFromStorage → secureRead return the decrypted array primed
// at boot.
const getBodyScanTensionHistory = () => {
  try {
    const raw = getSessionsFromStorage();
    if (!Array.isArray(raw)) return [];
    return raw
      .filter(s => Array.isArray(s?.tools) && s.tools.includes("body-scan"))
      .filter(s => s?.bodyScanTension && Object.keys(s.bodyScanTension).length > 0)
      .map(s => ({
        timestamp: s.timestamp || null,
        bodyScanTension: s.bodyScanTension,
        durationFormatted: s.durationFormatted || null
      }))
      .sort((a, b) => new Date(a.timestamp || 0).getTime() - new Date(b.timestamp || 0).getTime());
  } catch { return []; }
};

// Get the latest tension level for each area across the most recent N records
// of a chosen source. Source: "morning" or "scan". Returns { areaName: 1-5 }
// using the most recent reading per area within the window.
const getLatestTensionByArea = (source = "morning", limit = 5) => {
  try {
    const records = source === "scan"
      ? getBodyScanTensionHistory()
      : getMorningTensionHistory();
    const recent = records.slice(-limit);
    const latest = {};
    recent.forEach(r => {
      const data = source === "scan" ? r.bodyScanTension : r.tension;
      Object.entries(data || {}).forEach(([area, level]) => {
        if (level > 0) latest[area] = level; // last write wins (chronological order preserved)
      });
    });
    return latest;
  } catch { return {}; }
};

// Get tension trend per area across the last N records of a source.
// Returns { areaName: { first, latest, delta, recordCount } } or null per area
// when there's only one or zero readings for that area in the window.
const getTensionTrend = (source = "morning", limit = 14) => {
  try {
    const records = source === "scan"
      ? getBodyScanTensionHistory()
      : getMorningTensionHistory();
    const recent = records.slice(-limit);
    if (recent.length < 2) return {};

    // Group readings by area
    const perArea = {};
    recent.forEach(r => {
      const data = source === "scan" ? r.bodyScanTension : r.tension;
      Object.entries(data || {}).forEach(([area, level]) => {
        if (level > 0) {
          if (!perArea[area]) perArea[area] = [];
          perArea[area].push({ ts: r.timestamp || r.date || null, level });
        }
      });
    });

    const trend = {};
    Object.entries(perArea).forEach(([area, readings]) => {
      if (readings.length < 2) return;
      const first = readings[0];
      const latest = readings[readings.length - 1];
      trend[area] = {
        first: first.level,
        latest: latest.level,
        delta: latest.level - first.level, // negative = improvement, positive = worsening
        recordCount: readings.length
      };
    });
    return trend;
  } catch { return {}; }
};

// Get morning→scan delta on the same Stillform day. The strongest signal
// Stillform has for proving practice works: tension before vs after a body
// scan, on the same day. Returns array of { date, area, before, after, delta }
// or [] if no same-day pairs exist. delta is post - pre; negative = better.
const getMorningToScanDelta = (limitDays = 30) => {
  try {
    const morning = getMorningTensionHistory();
    const scans = getBodyScanTensionHistory();

    // Index morning by Stillform-day (uses date if available, else timestamp prefix)
    const morningByDay = {};
    morning.forEach(m => {
      const day = m.date || (m.timestamp ? String(m.timestamp).slice(0, 10) : null);
      if (day) morningByDay[day] = m.tension;
    });

    // For each body scan, find same-day morning tension and compute delta per area
    const pairs = [];
    scans.forEach(s => {
      const day = s.timestamp ? String(s.timestamp).slice(0, 10) : null;
      if (!day) return;
      const morningTension = morningByDay[day];
      if (!morningTension) return;
      Object.entries(s.bodyScanTension || {}).forEach(([area, after]) => {
        const before = morningTension[area];
        if (typeof before === "number" && before > 0 && typeof after === "number") {
          pairs.push({ date: day, area, before, after, delta: after - before });
        }
      });
    });

    // Cap at limitDays of same-day pairs (sorted by date desc)
    pairs.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    return pairs.slice(0, limitDays * BODY_SCAN_AREAS.length); // generous cap per area
  } catch { return []; }
};

// ─── EOD HISTORY HELPERS — Phase 0 for My Progress redesign ────────────
// EOD records capture: { date, timestamp, energy, composure, word, morningEnergy }
// where:
//   energy:        eod-end-of-day energy reading ("low" | "same" | "high" etc)
//   composure:     self-rated composure that day. Layer 2.37 source-of-truth
//                  (line 19532 chip picker): user picks Solid | Mixed | Rough,
//                  stored lowercase as "solid" | "mixed" | "rough". Legacy
//                  fallback default at lines 19425/19474/19482/19487 if user
//                  didn't pick: "mostly". Old schema "strong" is never
//                  written by any code path.
//   word:          optional one-word reflection from user
//   morningEnergy: snapshot of that morning's energy for pre/post compare
//
// Persistence gap fixed May 6, 2026: trackEodComplete now passes the full
// record (was only passing { date, timestamp, composure } before, dropping
// energy, word, and morningEnergy from history). Records before that fix
// will only have the partial shape; helpers handle missing fields gracefully.

// Get all EOD records sorted oldest-first.
// READ PATH (audit philosophy v1.3 Layer 2.39 Path A migration, May 8 2026):
// stillform_eod_history is in SECURE_KEYS and now actually encrypted at rest.
// Writes flow through appendDailyLoopHistory's secure branch (line ~5163) →
// secureWrite → CryptoStore.encrypt → localStorage.setItem(__enc envelope).
// Reads flow through secureRead, which returns the decrypted array primed
// by primeSecureCache at boot.
const getEodHistory = () => {
  try {
    const raw = secureRead("stillform_eod_history", []);
    if (!Array.isArray(raw)) return [];
    return raw
      .map(c => ({
        timestamp: c.timestamp || null,
        date: c.date || null,
        energy: c.energy || null,
        composure: c.composure || null,
        word: c.word || null,
        morningEnergy: c.morningEnergy || null
      }))
      .sort((a, b) => {
        const at = new Date(a.timestamp || a.date || 0).getTime();
        const bt = new Date(b.timestamp || b.date || 0).getTime();
        return at - bt;
      });
  } catch { return []; }
};

// Composure trend across last N EOD records.
// Layer 2.37 source-of-truth (line 19532 chip picker): real schema is
// solid | mixed | rough, with legacy fallback "mostly" when user submits
// without picking. Original code counted "strong | mostly | rough" — wrong
// schema, silently dropped the two most-common picks (solid, mixed) and the
// "strong" bucket never incremented. Fixed v1.3.
//
// Returns { solid, mixed, rough, mostly, total,
//           ratio: { solid, mixed, rough, mostly } } or null if no records.
const getComposureTrend = (limit = 14) => {
  try {
    const recent = getEodHistory().slice(-limit).filter(r => r.composure);
    if (recent.length === 0) return null;
    const counts = { solid: 0, mixed: 0, rough: 0, mostly: 0 };
    recent.forEach(r => {
      if (counts[r.composure] !== undefined) counts[r.composure]++;
    });
    const total = recent.length;
    return {
      ...counts,
      total,
      ratio: {
        solid: total > 0 ? counts.solid / total : 0,
        mixed: total > 0 ? counts.mixed / total : 0,
        rough: total > 0 ? counts.rough / total : 0,
        mostly: total > 0 ? counts.mostly / total : 0
      }
    };
  } catch { return null; }
};

// Energy delta morning→evening across same-day pairs. Captures whether
// energy *recovered* (morning low → evening high) or *drained* (morning
// high → evening low) on each day. Returns array of { date, morning, evening }
// for each day where both readings exist.
const getEnergyArc = (limitDays = 30) => {
  try {
    const eod = getEodHistory().slice(-limitDays);
    return eod
      .filter(r => r.energy && r.morningEnergy)
      .map(r => ({
        date: r.date,
        morning: r.morningEnergy,
        evening: r.energy
      }))
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  } catch { return []; }
};

// Get all words from EOD reflections (for word-cloud or trend display).
// Returns array of { date, word } or empty if no word reflections exist.
const getEodReflections = (limit = 30) => {
  try {
    return getEodHistory()
      .filter(r => r.word && String(r.word).trim().length > 0)
      .slice(-limit)
      .map(r => ({ date: r.date, word: String(r.word).trim() }))
      .reverse(); // newest first for surfacing
  } catch { return []; }
};

// ─── EOD ARTIFACT — Engagement Architecture Engine 2, Build #10 (frontend) ──
// Spec: STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.2 ("EOD artifact: 2-sentence
// summary of what the day taught the user, accumulating into a vocabulary of
// their own life. Distinct from the user's freewrite — this one is the
// AI-named takeaway."). Backend at netlify/functions/eod-artifact.js
// (commit 4c36283) returns { artifact, generatedAt } from gpt-4o; voice
// rubric is locked in the system prompt (prestige-operator declarative,
// exactly two sentences, no advice, no "tomorrow," no platitudes).
//
// READ/WRITE PATH (audit philosophy v1.3 Layer 2.39):
// stillform_eod_artifacts is in SECURE_KEYS (encrypted at rest, parallel to
// journal / signal profile / bias profile / EOD history). Writes via
// secureWrite, reads via secureRead. SecureCache is primed at boot.
//
// FAILURE MODE on AI-down / timeout / voice violation: skip silent — no
// artifact persisted for that day. A deterministic template would betray
// the voice rubric (the artifact's value IS specificity to the user's day;
// a generic fallback line is worse than no line). The vocabulary tolerates
// gaps the way a real journal does.
//
// TRIGGER: fire-and-forget from EOD save flow (line ~20256), after
// trackEodComplete. Does not block the user-visible save path.
const EOD_ARTIFACT_API_URL = (() => {
  try {
    const isCapacitor = window?.Capacitor?.isNativePlatform?.();
    return isCapacitor
      ? "https://stillformapp.com/.netlify/functions/eod-artifact"
      : "/.netlify/functions/eod-artifact";
  } catch {
    return "/.netlify/functions/eod-artifact";
  }
})();
const EOD_ARTIFACTS_STORAGE_KEY = "stillform_eod_artifacts";
const EOD_ARTIFACTS_MAX_ITEMS = 90; // ~3 months of vocabulary; older trims

// Get all EOD artifacts oldest-first. Returns [] on any read error.
// Each record: { date: "YYYY-MM-DD", artifact: string, generatedAt: ISO }.
const getEodArtifacts = () => {
  try {
    const raw = secureRead(EOD_ARTIFACTS_STORAGE_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

// Persist an artifact, replacing any existing record for the same date so
// re-fires (after EOD update) overwrite cleanly. Trims to MAX_ITEMS oldest-out.
const appendEodArtifact = (record) => {
  if (!record?.date || !record?.artifact) return null;
  try {
    const existing = getEodArtifacts();
    const filtered = existing.filter(r => r.date !== record.date);
    filtered.push({
      date: record.date,
      artifact: String(record.artifact).slice(0, 400),
      generatedAt: record.generatedAt || new Date().toISOString()
    });
    const trimmed = filtered.length > EOD_ARTIFACTS_MAX_ITEMS
      ? filtered.slice(-EOD_ARTIFACTS_MAX_ITEMS)
      : filtered;
    secureWrite(EOD_ARTIFACTS_STORAGE_KEY, trimmed);
    return record;
  } catch { return null; }
};

// Build the day-snapshot payload from existing storage. All field reads
// align with actual write paths (Layer 1.1 + 2.39 verified):
//   stillform_eod_today    — { date, energy, composure, word, morningEnergy }
//   stillform_sessions     — [{ timestamp, tools, preState, postState, delta, ... }]
// Backend (eod-artifact.js lines 151-162) bounds these server-side too;
// client truncation here is defense-in-depth, not the security boundary.
const buildEodArtifactPayload = (eodToday) => {
  const today = TimeKeeper.stillformDay();
  let sessionsToday = [];
  try {
    const all = secureRead("stillform_sessions", []);
    sessionsToday = (Array.isArray(all) ? all : []).filter(s => {
      try { return TimeKeeper.stillformDayOf(s.timestamp) === today; }
      catch { return false; }
    });
  } catch {}
  const toolsUsed = Array.from(new Set(
    sessionsToday.flatMap(s => Array.isArray(s.tools) ? s.tools : []).filter(Boolean)
  ));
  const feelStatesToday = Array.from(new Set(
    sessionsToday.flatMap(s => [s.preState, s.postState]).filter(Boolean)
  ));
  const recentShifts = sessionsToday
    .filter(s => s.preState && s.postState)
    .slice(-5)
    .map(s => ({
      pre: String(s.preState),
      post: String(s.postState),
      delta: Number.isFinite(s.delta) ? s.delta : null
    }));
  // Stage 4 — patterns the user self-flagged in today's sessions. Distinct
  // from the rolling formatUserFlaggedPatternsForAI window: scoped to today
  // only so the EOD artifact can credit today's catches specifically.
  const patternsCaughtToday = Array.from(new Set(
    sessionsToday.map(s => s.flaggedPattern).filter(Boolean)
  ));
  return {
    eodEnergy: eodToday?.energy || "",
    eodComposure: eodToday?.composure || "",
    eodWord: eodToday?.word || "",
    morningEnergy: eodToday?.morningEnergy || "",
    // May 14, 2026 — captivated EOD passes the anticipated tomorrow load
    // chip selection through to the AI so the artifact can close the loop
    // forward-looking when it's set. Backend (eod-artifact.js) can use or
    // ignore this field; client always sends it for forward compatibility.
    onTheTableTomorrow: eodToday?.onTheTableTomorrow || "",
    sessionsToday: sessionsToday.length,
    toolsUsed,
    feelStatesToday,
    recentShifts,
    patternsCaughtToday
  };
};

// Fire-and-forget. Returns a promise that resolves to the persisted record
// on success or null on any failure (network, 4xx, 5xx, parse error, empty
// artifact). Caller does not need to await — the EOD save UI proceeds
// regardless. On success, the new vocabulary entry is in storage and will
// sync up via the normal SYNC_KEYS path on next launch / refresh.
const generateEodArtifact = async (eodToday) => {
  if (!eodToday?.date) return null;
  try {
    const payload = buildEodArtifactPayload(eodToday);
    const response = await fetch(EOD_ARTIFACT_API_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) {
      // Telemetry per master todo line 139 — measure AI-down rate +
      // failure-mode frequency in production. Net status only; no PII.
      try { window.plausible?.("EOD Artifact Generation Failed", { props: { reason: `http-${response.status}` } }); } catch {}
      return null;
    }
    const data = await response.json();
    const artifact = typeof data?.artifact === "string" ? data.artifact.trim() : "";
    if (!artifact) {
      try { window.plausible?.("EOD Artifact Generation Failed", { props: { reason: "empty-artifact" } }); } catch {}
      return null;
    }
    const generatedAt = typeof data?.generatedAt === "string"
      ? data.generatedAt
      : new Date().toISOString();
    const persisted = appendEodArtifact({ date: eodToday.date, artifact, generatedAt });
    // Success branch — fire after persist, so the event reflects what
    // actually landed in the user's storage tier, not just the wire return.
    try {
      window.plausible?.("EOD Artifact Generated", {
        props: { length: String(artifact.length) }
      });
    } catch {}
    return persisted;
  } catch (err) {
    try {
      window.plausible?.("EOD Artifact Generation Failed", {
        props: { reason: err?.name === "AbortError" ? "timeout" : "network" }
      });
    } catch {}
    return null;
  }
};

// ─── TODAY'S BRIEF — Engagement Architecture Engine 2, Build #3 (frontend) ──
// Spec: STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.2 lines 121-126 ("Morning
// artifact summarizing hardware + risks + moves + recovery. Generated at
// morning check-in from bio-filter + outcome focus + calendar + Trigger
// Profile + bias profile. Re-readable all day. AI-generated, brand-voice
// locked."). Audit doc: TODAYS_BRIEF_FLOW_AUDIT.md (May 8). Backend at
// netlify/functions/todays-brief.js (Phase 3a, commit be4f23d) returns
// { hardware, risks, moves, recovery, generatedAt } structured JSON via
// gpt-4o response_format json_object.
//
// READ/WRITE PATH:
// stillform_todays_briefs joins SECURE_KEYS (encrypted at rest, parallel
// to journal / profiles / eod_artifacts) and SYNC_KEYS (cross-device).
//
// FAILURE MODE on AI-down / timeout / schema violation: skip silent — no
// brief persisted. Same posture as EOD artifact. The morning-compass value
// IS specificity to the user's day; a generic fallback would betray the
// voice rubric. Silent absence is the right surface.
//
// TRIGGER: fire-and-forget from saveCheckin (Phase 3c, ships next), after
// trackMorningComplete. Does not block the user-visible check-in close.
const TODAYS_BRIEF_API_URL = (() => {
  try {
    const isCapacitor = window?.Capacitor?.isNativePlatform?.();
    return isCapacitor
      ? "https://stillformapp.com/.netlify/functions/todays-brief"
      : "/.netlify/functions/todays-brief";
  } catch {
    return "/.netlify/functions/todays-brief";
  }
})();
const TODAYS_BRIEFS_STORAGE_KEY = "stillform_todays_briefs";
const TODAYS_BRIEFS_MAX_ITEMS = 90; // ~3 months parallel to EOD artifacts

// Get all Today's Briefs oldest-first. Returns [] on any read error.
// Each record:
//   { date: "YYYY-MM-DD", hardware, risks, moves, recovery, generatedAt: ISO }
const getTodaysBriefs = () => {
  try {
    const raw = secureRead(TODAYS_BRIEFS_STORAGE_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

// Persist a brief, replacing any existing record for the same date so
// re-fires (after morning check-in update) overwrite cleanly. Trims to
// MAX_ITEMS oldest-out, same policy as EOD artifacts.
const appendTodaysBrief = (record) => {
  if (!record?.date || !record?.hardware) return null;
  try {
    const existing = getTodaysBriefs();
    const filtered = existing.filter(r => r.date !== record.date);
    filtered.push({
      date: record.date,
      hardware: String(record.hardware).slice(0, 280),
      risks: String(record.risks || "").slice(0, 280),
      moves: String(record.moves || "").slice(0, 280),
      recovery: String(record.recovery || "").slice(0, 280),
      generatedAt: record.generatedAt || new Date().toISOString()
    });
    const trimmed = filtered.length > TODAYS_BRIEFS_MAX_ITEMS
      ? filtered.slice(-TODAYS_BRIEFS_MAX_ITEMS)
      : filtered;
    secureWrite(TODAYS_BRIEFS_STORAGE_KEY, trimmed);
    return record;
  } catch { return null; }
};

// Convenience: today's brief if it exists, else null. Read by the inline
// display in Phase 3d so the check-in close screen renders the brief if
// it's already arrived (or shows a placeholder if AI is still in flight).
const getTodaysBriefForToday = () => {
  try {
    const today = TimeKeeper.stillformDay();
    return getTodaysBriefs().find(r => r.date === today) || null;
  } catch { return null; }
};

// May 14, 2026 — captivated EOD parallel to Today's Brief. Reads today's
// EOD artifact for inline display in the saved-state branch + open form
// once generation lands. Same shape as getTodaysBriefForToday — returns
// the artifact record { date, artifact, generatedAt } or null.
const getEodArtifactForToday = () => {
  try {
    const today = TimeKeeper.stillformDay();
    return getEodArtifacts().find(r => r.date === today) || null;
  } catch { return null; }
};

// Build the morning-snapshot payload from existing storage. All field reads
// align with actual write paths. Backend (todays-brief.js) bounds these
// server-side too; client truncation here is defense-in-depth, not the
// security boundary.
//
// Pre-formatted profile strings (signalProfile, biasProfile, triggerProfile)
// mirror the inline IIFE pattern Reframe uses (line ~10030+) so the AI
// receives identical context shape across surfaces.
const buildTodaysBriefPayload = (checkinToday) => {
  // Morning state
  const morningEnergy = checkinToday?.energy || "";
  const morningMood = checkinToday?.mood || "";
  const bioFilter = Array.isArray(checkinToday?.bio) ? checkinToday.bio : [];
  const tensionAreas = checkinToday?.tension && typeof checkinToday.tension === "object"
    ? Object.keys(checkinToday.tension).filter(k => Number(checkinToday.tension[k]) > 0)
    : [];

  // Outcome focus — what they want to be true today
  let outcomeFocus = "";
  try {
    const raw = localStorage.getItem("stillform_outcome_focus");
    if (raw) {
      const parsed = JSON.parse(raw);
      outcomeFocus = String(parsed?.text || parsed?.value || raw || "");
    }
  } catch {}

  // Calendar — events array if present, summary string as fallback
  let calendarEvents = [];
  let calendarSummary = "";
  try {
    const ev = JSON.parse(localStorage.getItem("stillform_calendar_events") || "[]");
    if (Array.isArray(ev)) {
      calendarEvents = ev
        .filter(e => e && e.title)
        .slice(0, 6)
        .map(e => ({ title: String(e.title), start: String(e.start || "") }));
    }
    calendarSummary = localStorage.getItem("stillform_calendar_summary") || "";
  } catch {}

  // Trigger Profile — pre-formatted via existing helper
  let triggerProfile = "";
  try { triggerProfile = formatTriggerProfileForAI(8) || ""; } catch {}

  // Match user's named triggers against today's calendar events. Same
  // substring rule as buildPreEventBriefPayload; here multi-event. Tells
  // the AI WHICH events match WHICH triggers so Risks get scoped specifically
  // rather than abstract.
  let matchedEventTriggers = "";
  try {
    const profile = getTriggerProfile();
    if (profile?.triggers?.length && calendarEvents.length) {
      const eventMatches = [];
      calendarEvents.forEach(ev => {
        const haystack = String(ev.title || "").toLowerCase();
        const matches = profile.triggers.filter(t => {
          const label = String(t.label || "").trim().toLowerCase();
          return label.length >= 2 && haystack.includes(label);
        });
        if (matches.length) {
          eventMatches.push(`"${ev.title}" → ${matches.map(m => m.label).join(", ")}`);
        }
      });
      if (eventMatches.length) {
        matchedEventTriggers = `Calendar events that reference user's named triggers: ${eventMatches.join("; ")}. Risks section should name these specifically.`;
      }
    }
  } catch {}

  // Bias profile — same inline formatting Reframe uses
  let biasProfile = "";
  try {
    const biases = secureRead("stillform_bias_profile", null);
    if (Array.isArray(biases) && biases.length) {
      biasProfile = `User's identified decision patterns: ${biases.join(", ")}`;
    }
  } catch {}

  // User-flagged patterns — pre-formatted via shared helper. Tells the AI
  // which patterns the user has caught themselves running recently.
  let userFlaggedPatterns = "";
  try { userFlaggedPatterns = formatUserFlaggedPatternsForAI() || ""; } catch {}

  // Signal profile — same inline formatting Reframe uses
  let signalProfile = "";
  try {
    const p = secureRead("stillform_signal_profile", null);
    if (p) {
      const parts = [];
      if (p.firstAreas?.length) parts.push(`Body signals first in: ${p.firstAreas.join(", ")}`);
      if (p.preSensations?.length) parts.push(`Pre-escalation sensations: ${p.preSensations.join(", ")}`);
      if (p.triggers?.length) parts.push(`Known triggers: ${p.triggers.join(", ")}`);
      signalProfile = parts.length ? parts.join(". ") : "";
    }
  } catch {}

  // Stage info via existing helper
  let stageId = null;
  let stageName = "";
  try {
    const snap = getCurrentStage();
    if (snap?.currentStageId) stageId = snap.currentStageId;
    if (snap?.stage?.name) stageName = String(snap.stage.name);
  } catch {}

  // Recent practice — last 7 days session count
  let recentSessionsCount = 0;
  const recentSessionDays = 7;
  try {
    const sessions = secureRead("stillform_sessions", []);
    if (Array.isArray(sessions)) {
      const cutoff = TimeKeeper.daysAgoMs(recentSessionDays);
      recentSessionsCount = sessions.filter(s => {
        try { return new Date(s.timestamp).getTime() >= cutoff; }
        catch { return false; }
      }).length;
    }
  } catch {}

  // Yesterday's EOD takeaway — give the morning brief continuity from the
  // evening artifact. Powerful narrative hook: morning compass references
  // what last night's compass named.
  let yesterdayEodArtifact = "";
  let yesterdayComposure = "";
  try {
    const yesterday = TimeKeeper.stillformYesterday();
    const briefs = getEodArtifacts();
    const y = briefs.find(r => r.date === yesterday);
    if (y?.artifact) yesterdayEodArtifact = String(y.artifact);
    const eodHistory = secureRead("stillform_eod_history", []);
    if (Array.isArray(eodHistory)) {
      const yEod = eodHistory.find(e => e.date === yesterday);
      if (yEod?.composure) yesterdayComposure = String(yEod.composure);
    }
  } catch {}

  return {
    morningEnergy,
    morningMood,
    bioFilter,
    tensionAreas,
    outcomeFocus,
    calendarEvents,
    calendarSummary,
    triggerProfile,
    matchedEventTriggers,
    biasProfile,
    userFlaggedPatterns,
    signalProfile,
    stageId,
    stageName,
    recentSessionsCount,
    recentSessionDays,
    yesterdayEodArtifact,
    yesterdayComposure
  };
};

// Fire-and-forget. Returns a promise that resolves to the persisted record
// on success or null on any failure. Caller does not need to await — the
// morning check-in close UI proceeds regardless. On success, today's brief
// is in storage and Phase 3d's render branch picks it up. Polling pattern
// is NOT used here — Phase 3d shows a placeholder while AI is in flight,
// and a useEffect-driven re-read picks up the persisted brief once
// generation completes.
const generateTodaysBrief = async (checkinToday) => {
  const today = TimeKeeper.stillformDay();
  if (!checkinToday) return null;
  try {
    const payload = buildTodaysBriefPayload(checkinToday);
    const response = await fetch(TODAYS_BRIEF_API_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) return null;
    const data = await response.json();
    const hardware = typeof data?.hardware === "string" ? data.hardware.trim() : "";
    if (!hardware) return null;
    const risks = typeof data?.risks === "string" ? data.risks.trim() : "";
    const moves = typeof data?.moves === "string" ? data.moves.trim() : "";
    const recovery = typeof data?.recovery === "string" ? data.recovery.trim() : "";
    const generatedAt = typeof data?.generatedAt === "string"
      ? data.generatedAt
      : new Date().toISOString();
    return appendTodaysBrief({ date: today, hardware, risks, moves, recovery, generatedAt });
  } catch { return null; }
};

// ─── PRE-EVENT BRIEF — Engagement Architecture Engine 2 Build #7 (frontend) ──
// Spec: STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.2 lines 128-130 verbatim:
//   "Same shape as Today's Brief, scoped to a specific calendar trigger.
//    Fires 30 minutes before. User has it on their phone walking into the room."
//
// Audit doc: PRE_EVENT_BRIEF_FLOW_AUDIT.md (May 8) §6 call 1 default —
// Option A (on-demand at notification tap). Backend at netlify/functions/
// pre-event-brief.js (Phase 7a, commit 1e3a121) returns same 4-key JSON
// (hardware/risks/moves/recovery) as Today's Brief, scoped to one event.
//
// READ/WRITE PATH:
// stillform_pre_event_briefs joins SECURE_KEYS (encrypted at rest, parallel
// to journal / profiles / eod_artifacts / todays_briefs) and SYNC_KEYS
// (cross-device). keyed by composite eventKey = "title|start" so
// rescheduled events get fresh briefs without manual cache invalidation.
//
// FAILURE MODE on AI-down / timeout / schema violation: skip silent — no
// brief persisted. Same posture as Today's Brief / EOD artifact. The
// moment-of-event value IS specificity to this user + this event; a
// generic fallback would betray the voice rubric. Silent absence is right.
//
// TRIGGER: fire-and-forget from the Pre-event Brief display screen on
// mount when no cached brief exists for that event-key (Phase 7d).

const PRE_EVENT_BRIEF_API_URL = (() => {
  try {
    const isCapacitor = window?.Capacitor?.isNativePlatform?.();
    return isCapacitor
      ? "https://stillformapp.com/.netlify/functions/pre-event-brief"
      : "/.netlify/functions/pre-event-brief";
  } catch {
    return "/.netlify/functions/pre-event-brief";
  }
})();
const PRE_EVENT_BRIEFS_STORAGE_KEY = "stillform_pre_event_briefs";
const PRE_EVENT_BRIEFS_MAX_ITEMS = 60; // ~2 weeks at 4-5 events/day

// Composite event key. title|start uniquely identifies a calendar event
// for cache lookup. If the event gets rescheduled (start changes), the
// new key generates a fresh brief. The old key becomes orphan and trims
// out at MAX_ITEMS oldest-out.
const buildPreEventBriefKey = (event) => {
  if (!event?.title) return null;
  const t = String(event.title).slice(0, 200);
  const s = String(event.start || "").slice(0, 40);
  return `${t}|${s}`;
};

// Get all Pre-event Briefs newest-first. Returns [] on any read error.
// Each record: { eventKey, eventTitle, eventStart, hardware, risks, moves,
// recovery, generatedAt }.
const getPreEventBriefs = () => {
  try {
    const raw = secureRead(PRE_EVENT_BRIEFS_STORAGE_KEY, []);
    if (!Array.isArray(raw)) return [];
    return [...raw].sort((a, b) =>
      new Date(b.generatedAt || 0).getTime() - new Date(a.generatedAt || 0).getTime()
    );
  } catch { return []; }
};

// Lookup by event. Returns the persisted brief for that event-key, or
// null. Used by Phase 7d display screen on mount to decide whether to
// render directly or fire generation + start polling.
const getPreEventBriefForEvent = (event) => {
  const key = buildPreEventBriefKey(event);
  if (!key) return null;
  try {
    return getPreEventBriefs().find(r => r.eventKey === key) || null;
  } catch { return null; }
};

// Persist a brief, replacing any existing record for the same event-key
// so re-fires after a rescheduled event overwrite cleanly. Trims to
// MAX_ITEMS oldest-out, same policy as Today's Brief / EOD artifacts.
const appendPreEventBrief = (record) => {
  if (!record?.eventKey || !record?.hardware) return null;
  try {
    const existing = getPreEventBriefs();
    const filtered = existing.filter(r => r.eventKey !== record.eventKey);
    filtered.push({
      eventKey: String(record.eventKey).slice(0, 240),
      eventTitle: String(record.eventTitle || "").slice(0, 200),
      eventStart: String(record.eventStart || "").slice(0, 40),
      hardware: String(record.hardware).slice(0, 280),
      risks: String(record.risks || "").slice(0, 280),
      moves: String(record.moves || "").slice(0, 280),
      recovery: String(record.recovery || "").slice(0, 280),
      generatedAt: record.generatedAt || new Date().toISOString()
    });
    const trimmed = filtered.length > PRE_EVENT_BRIEFS_MAX_ITEMS
      ? filtered.slice(-PRE_EVENT_BRIEFS_MAX_ITEMS)
      : filtered;
    secureWrite(PRE_EVENT_BRIEFS_STORAGE_KEY, trimmed);
    return record;
  } catch { return null; }
};

// Build the per-event payload. Reuses Today's Brief's state-context shape
// verbatim (bio-filter, tension, outcome focus, profiles, stage, recent
// practice, yesterday's EOD) plus event-specific fields. Backend
// (pre-event-brief.js) bounds these server-side too; client truncation
// here is defense-in-depth.
const buildPreEventBriefPayload = (event) => {
  // Event details (the new surface vs Today's Brief)
  const eventTitle = String(event?.title || "");
  const eventStart = String(event?.start || "");
  const eventDescription = String(event?.description || "");

  // Read morning check-in for state. Same path Today's Brief uses.
  let morningEnergy = "";
  let morningMood = "";
  let bioFilter = [];
  let tensionAreas = [];
  try {
    const ci = JSON.parse(localStorage.getItem("stillform_checkin_today") || "null");
    if (ci?.date === TimeKeeper.stillformDay()) {
      morningEnergy = ci.energy || "";
      morningMood = ci.mood || "";
      bioFilter = Array.isArray(ci.bio) ? ci.bio : [];
      tensionAreas = ci.tension && typeof ci.tension === "object"
        ? Object.keys(ci.tension).filter(k => Number(ci.tension[k]) > 0)
        : [];
    }
  } catch {}

  // Outcome focus
  let outcomeFocus = "";
  try {
    const raw = localStorage.getItem("stillform_outcome_focus");
    if (raw) {
      const parsed = JSON.parse(raw);
      outcomeFocus = String(parsed?.text || parsed?.value || raw || "");
    }
  } catch {}

  // Trigger Profile — pre-formatted via existing helper
  let triggerProfile = "";
  try { triggerProfile = formatTriggerProfileForAI(8) || ""; } catch {}

  // Phase 7e — Trigger Profile match detection. Case-insensitive substring
  // match of any Trigger Profile entry label against the event title +
  // description. Audit §3 7e listed "substring? fuzzy? embeddings?" as the
  // open question; substring is the simplest viable shipped first. Matched
  // triggers pass as a separate field so the AI knows which load-bearing
  // patterns this event references.
  let matchedTriggers = "";
  try {
    const profile = getTriggerProfile();
    if (profile?.triggers?.length) {
      const haystack = `${eventTitle} ${eventDescription}`.toLowerCase();
      const matches = profile.triggers.filter(t => {
        const label = String(t.label || "").trim().toLowerCase();
        return label.length >= 2 && haystack.includes(label);
      });
      if (matches.length) {
        matchedTriggers = `Trigger Profile match — this event references: ${matches.map(m => `"${m.label}" [${m.category}]`).join(", ")}`;
      }
    }
  } catch {}

  // Bias profile — same inline format Reframe uses
  let biasProfile = "";
  try {
    const biases = secureRead("stillform_bias_profile", null);
    if (Array.isArray(biases) && biases.length) {
      biasProfile = `User's identified decision patterns: ${biases.join(", ")}`;
    }
  } catch {}

  // User-flagged patterns — same shared helper used by Today's Brief.
  let userFlaggedPatterns = "";
  try { userFlaggedPatterns = formatUserFlaggedPatternsForAI() || ""; } catch {}

  // Signal profile — same inline format Reframe uses
  let signalProfile = "";
  try {
    const p = secureRead("stillform_signal_profile", null);
    if (p) {
      const parts = [];
      if (p.firstAreas?.length) parts.push(`Body signals first in: ${p.firstAreas.join(", ")}`);
      if (p.preSensations?.length) parts.push(`Pre-escalation sensations: ${p.preSensations.join(", ")}`);
      if (p.triggers?.length) parts.push(`Known triggers: ${p.triggers.join(", ")}`);
      signalProfile = parts.length ? parts.join(". ") : "";
    }
  } catch {}

  // Stage info
  let stageId = null;
  let stageName = "";
  try {
    const snap = getCurrentStage();
    if (snap?.currentStageId) stageId = snap.currentStageId;
    if (snap?.stage?.name) stageName = String(snap.stage.name);
  } catch {}

  // Recent practice — last 7 days
  let recentSessionsCount = 0;
  const recentSessionDays = 7;
  try {
    const sessions = secureRead("stillform_sessions", []);
    if (Array.isArray(sessions)) {
      const cutoff = TimeKeeper.daysAgoMs(recentSessionDays);
      recentSessionsCount = sessions.filter(s => {
        try { return new Date(s.timestamp).getTime() >= cutoff; }
        catch { return false; }
      }).length;
    }
  } catch {}

  // Yesterday's EOD takeaway — same continuity hook Today's Brief uses
  let yesterdayEodArtifact = "";
  try {
    const yesterday = TimeKeeper.stillformYesterday();
    const briefs = getEodArtifacts();
    const y = briefs.find(r => r.date === yesterday);
    if (y?.artifact) yesterdayEodArtifact = String(y.artifact);
  } catch {}

  return {
    eventTitle,
    eventStart,
    eventDescription,
    morningEnergy,
    morningMood,
    bioFilter,
    tensionAreas,
    outcomeFocus,
    triggerProfile,
    matchedTriggers,
    biasProfile,
    userFlaggedPatterns,
    signalProfile,
    stageId,
    stageName,
    recentSessionsCount,
    recentSessionDays,
    yesterdayEodArtifact
  };
};

// Fire-and-forget. Returns a promise that resolves to the persisted record
// on success or null on any failure. Caller (Phase 7d display screen) does
// not need to await — the polling pattern picks up the persisted brief
// once generation completes.
const generatePreEventBrief = async (event) => {
  if (!event?.title) return null;
  const eventKey = buildPreEventBriefKey(event);
  if (!eventKey) return null;
  try {
    const payload = buildPreEventBriefPayload(event);
    const response = await fetch(PRE_EVENT_BRIEF_API_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) return null;
    const data = await response.json();
    const hardware = typeof data?.hardware === "string" ? data.hardware.trim() : "";
    if (!hardware) return null;
    const risks = typeof data?.risks === "string" ? data.risks.trim() : "";
    const moves = typeof data?.moves === "string" ? data.moves.trim() : "";
    const recovery = typeof data?.recovery === "string" ? data.recovery.trim() : "";
    const generatedAt = typeof data?.generatedAt === "string"
      ? data.generatedAt
      : new Date().toISOString();
    return appendPreEventBrief({
      eventKey,
      eventTitle: event.title,
      eventStart: event.start || "",
      hardware,
      risks,
      moves,
      recovery,
      generatedAt
    });
  } catch { return null; }
};

// ─── MOVE CARD HISTORY — Engagement Architecture Engine 2 Build #8 Phase 8e ──
// Records every Move card session (completed or early-exit) to a persistent
// history. Drives two consumer paths: (1) recentMoveIds passed to selection
// so the AI / deterministic fallback can vary sequences across summons
// (orienting-response mechanism degrades on repeat); (2) future surfacing
// in My Progress / engagement charts.
//
// Schema per entry:
//   { sequenceId, durationMs, completed, pathway, sequenceState, reason, timestamp }
//
// Storage: stillform_move_card_history. Joins SECURE_KEYS (encrypted at rest,
// parallel to disruptor_sessions / sessions / journal) + SYNC_KEYS (cross-
// device) + keysToRemove (delete-all path). Cap 200 entries oldest-out.

const MOVE_CARD_HISTORY_STORAGE_KEY = "stillform_move_card_history";
const MOVE_CARD_HISTORY_MAX_ITEMS = 200;

// Get all Move card history entries, newest-first.
const getMoveCardHistory = () => {
  try {
    const raw = secureRead(MOVE_CARD_HISTORY_STORAGE_KEY, []);
    if (!Array.isArray(raw)) return [];
    return [...raw].sort((a, b) =>
      new Date(b.timestamp || 0).getTime() - new Date(a.timestamp || 0).getTime()
    );
  } catch { return []; }
};

// Append a new entry. Trims to MAX_ITEMS oldest-out. Returns the persisted
// record on success, null on any failure. Caller does not need to await
// or check — the Move card UX proceeds regardless.
const appendMoveCardHistory = (record) => {
  if (!record?.sequenceId) return null;
  try {
    const existing = getMoveCardHistory();
    const persisted = {
      sequenceId: String(record.sequenceId).slice(0, 80),
      durationMs: Number.isFinite(record.durationMs) ? record.durationMs : 0,
      completed: Boolean(record.completed),
      pathway: String(record.pathway || "unknown").slice(0, 32),
      sequenceState: record.sequenceState && typeof record.sequenceState === "object"
        ? record.sequenceState : null,
      reason: typeof record.reason === "string" ? record.reason.slice(0, 200) : null,
      timestamp: record.timestamp || new Date().toISOString()
    };
    // Newest-first; cap from the tail (oldest entries)
    const next = [persisted, ...existing];
    const trimmed = next.length > MOVE_CARD_HISTORY_MAX_ITEMS
      ? next.slice(0, MOVE_CARD_HISTORY_MAX_ITEMS)
      : next;
    secureWrite(MOVE_CARD_HISTORY_STORAGE_KEY, trimmed);
    return persisted;
  } catch { return null; }
};

// Recent sequenceIds for variety. Returns the last N completed-or-not
// sequenceIds in newest-first order. Passed to selection so the AI can
// avoid recent repeats. Variety matters because the orienting-response
// mechanism (Sokolov 1963) degrades on repetition — same move twice in a
// row captures less novelty.
const getRecentMoveCardIds = (limit = 5) => {
  try {
    return getMoveCardHistory().slice(0, limit).map(r => r.sequenceId).filter(Boolean);
  } catch { return []; }
};

// ─── SAVED REFRAMES INVENTORY HELPERS — Phase 0 for My Progress redesign ───
// Saved reframes record: { text, distortion, timestamp, mode } where mode is
// "calm" | "clarity" | "hype". Stored in stillform_saved_reframes (encrypted).
//
// These helpers normalize the inventory for surfacing in My Progress without
// requiring the screen to know the storage key or shape.

// Get all saved reframes, newest-first (typical surfacing order).
const getSavedReframes = (limit = 50) => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return [];
    return [...raw]
      .sort((a, b) => new Date(b.timestamp || 0).getTime() - new Date(a.timestamp || 0).getTime())
      .slice(0, limit);
  } catch { return []; }
};

// Count saved reframes by mode. Returns { calm, clarity, hype, total }.
// Useful for surfacing "you've saved 7 calm reframes, 2 hype" patterns.
const getSavedReframeCounts = () => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return { calm: 0, clarity: 0, hype: 0, total: 0 };
    const counts = { calm: 0, clarity: 0, hype: 0, total: raw.length };
    raw.forEach(r => {
      const mode = String(r.mode || "").toLowerCase();
      if (counts[mode] !== undefined) counts[mode]++;
    });
    return counts;
  } catch { return { calm: 0, clarity: 0, hype: 0, total: 0 }; }
};

// Distortion frequency across saved reframes. Returns { distortion: count }
// sorted by count descending. Useful for surfacing user's most-recurring
// thinking patterns ("you've named catastrophizing 12 times this month").
const getSavedReframeDistortions = (limitDays = 90) => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return [];
    const cutoff = TimeKeeper.daysAgoMs(limitDays);
    const counts = {};
    raw
      .filter(r => r.distortion && new Date(r.timestamp || 0).getTime() >= cutoff)
      .forEach(r => {
        const d = String(r.distortion).trim();
        if (d) counts[d] = (counts[d] || 0) + 1;
      });
    return Object.entries(counts)
      .map(([distortion, count]) => ({ distortion, count }))
      .sort((a, b) => b.count - a.count);
  } catch { return []; }
};

// ─── SESSIONS INVENTORY HELPERS — Phase 0 for My Progress ─────────────
// computeStreak, countTodaysSessions, getMostRecentSession already exist
// near line 2350 (added earlier in May 6 home-screen feature commits).
// These are the rollup helpers My Progress will need: week/month windows,
// tool distribution, average session duration.

// Count sessions in the last N stillform-days. Includes today.
// Default 7 = "this week" rolling window.
const countSessionsInDays = (days = 7) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    return getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    }).length;
  } catch { return 0; }
};

// Tool usage distribution across last N days. Returns
// { breathe, scan, reframe, metacognition, ground, total } where each value
// is the count of sessions that included that tool. (Sessions can include
// multiple tools — e.g. breathe + ground.) Default 30 days.
const getToolDistribution = (days = 30) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    const sessions = getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    });
    const counts = { breathe: 0, "body-scan": 0, reframe: 0, metacognition: 0, ground: 0, total: sessions.length };
    sessions.forEach(s => {
      const tools = Array.isArray(s.tools) ? s.tools : [];
      tools.forEach(t => {
        if (counts[t] !== undefined) counts[t]++;
      });
    });
    return counts;
  } catch { return { breathe: 0, "body-scan": 0, reframe: 0, metacognition: 0, ground: 0, total: 0 }; }
};

// Average session duration (in seconds) across last N sessions. Returns null
// if no sessions or no duration data. Used for "your average session is N
// minutes" surface.
const getAverageSessionDuration = (limit = 30) => {
  try {
    const recent = getSessionsFromStorage()
      .filter(s => typeof s.duration === "number" && s.duration > 0)
      .slice(-limit);
    if (!recent.length) return null;
    const total = recent.reduce((sum, s) => sum + s.duration, 0);
    return Math.round(total / recent.length);
  } catch { return null; }
};

// Sessions per stillform-day across last N days. Returns array of
// { date, count } sorted oldest-first. Surfaces practice rhythm — does
// the user practice consistently, in bursts, or sporadically? Default 30.
const getSessionsPerDay = (days = 30) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    const sessions = getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    });
    const byDay = {};
    sessions.forEach(s => {
      const day = TimeKeeper.stillformDayOf(s.timestamp);
      if (day) byDay[day] = (byDay[day] || 0) + 1;
    });
    return Object.entries(byDay)
      .map(([date, count]) => ({ date, count }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  } catch { return []; }
};

// ─── FOCUS CHECK HISTORY HELPERS — Phase 0 for My Progress ────────────
// Focus check (Composure Check) records: { timestamp, trials, accuracy,
// inhibition, avgReactionMs, falseAlarms }. 20-record cap (acknowledged
// in master todo as sufficient for trend analysis but capped depth).
//
// Storage: stillform_focus_check_history (encrypted).
//
// These helpers expose the trend My Progress will need to surface:
// recognition speed and inhibition both improving over time is direct
// evidence of the cognitive function the practice trains.

// Get focus check history sorted oldest-first.
const getFocusCheckHistory = () => {
  try {
    const raw = secureRead("stillform_focus_check_history", []);
    if (!Array.isArray(raw)) return [];
    return [...raw].sort((a, b) => {
      const at = new Date(a.timestamp || 0).getTime();
      const bt = new Date(b.timestamp || 0).getTime();
      return at - bt;
    });
  } catch { return []; }
};

// Trend across focus check history. Returns { first, latest, deltaAccuracy,
// deltaInhibition, deltaReactionMs, recordCount } or null if fewer than 2.
// Negative deltaReactionMs = faster (improvement). Positive deltaAccuracy/
// deltaInhibition = improvement. Used for surfacing "your composure check
// reaction time has dropped from X to Y" (the spec language explicitly
// called out as a recognition-through-evidence framing).
const getFocusCheckTrend = (limit = 10) => {
  try {
    const records = getFocusCheckHistory().slice(-limit);
    if (records.length < 2) return null;
    const first = records[0];
    const latest = records[records.length - 1];
    return {
      first,
      latest,
      recordCount: records.length,
      deltaAccuracy: typeof first.accuracy === "number" && typeof latest.accuracy === "number"
        ? latest.accuracy - first.accuracy
        : null,
      deltaInhibition: typeof first.inhibition === "number" && typeof latest.inhibition === "number"
        ? latest.inhibition - first.inhibition
        : null,
      deltaReactionMs: typeof first.avgReactionMs === "number" && typeof latest.avgReactionMs === "number"
        ? latest.avgReactionMs - first.avgReactionMs
        : null
    };
  } catch { return null; }
};

const appendCommunicationEvent = (entry, maxItems = COMMUNICATION_EVENTS_MAX_ITEMS) => {
  if (!entry) return 0;
  const events = readArrayFromStorage(COMMUNICATION_EVENTS_KEY);
  events.push(entry);
  const bounded = events.slice(-maxItems);
  try { secureWrite(COMMUNICATION_EVENTS_KEY, bounded); } catch {}
  return bounded.length;
};

// ═══════════════════════════════════════════════════════════════════════
// ENGAGEMENT ARCHITECTURE — STAGE DEFINITIONS (Phase 0 — May 7, 2026)
// ═══════════════════════════════════════════════════════════════════════
//
// Five-stage developmental architecture mapping the metacognition practice.
// Stages build sequentially — each capacity prerequisites the next.
//
// Spec source of truth: STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.1
// Stage NAMES locked May 7, 2026.
// THRESHOLD VALUES first-pass — tunable post-launch against cohort data.
// Markers attach to existing data sources where shipped; deferred markers
// flagged with status:"deferred" until their data source ships.
//
// What ships in this Phase 0: data layer ONLY. No UI. The Mirror surface
// (home), Achievement micro-credits (close moments), and Roadmap screen
// (My Progress) all consume getCurrentStage() — they ship in subsequent
// phases per STILLFORM_ENGAGEMENT_ARCHITECTURE.md §10 shipping order.
//
// Honest adaptations from spec where data isn't available today:
//   - Stage 1 "autonomous exits" marker requires new instrumentation
//     (no current data trail for "user named state but didn't run a
//     tool"). Marked status:"deferred". Other Stage 1 markers ship.
//   - Stage 1 "active state entry" marker needs bio-filter persisted
//     ON each session entry. Today only the latest bio-filter is in
//     localStorage. Marked status:"deferred" pending instrumentation.
//   - Stage 2 affect-labeling latency + accuracy markers depended on
//     Practice Signals data. Practice Signals reverted entirely on
//     May 7. Marked status:"deferred" until Practice Signals rebuilds.
//   - Stage 3 markers gated on Trigger Profile (Build #2) and
//     Pre-event Brief (Build #7). Until those ship, all Stage 3
//     markers return met:false. By design — sequential build order.
//   - Stage 4 "user-flagged pattern preceding AI detection" requires
//     a new flag in journal/EOD entries. Marked status:"deferred".
//   - Stage 5 "high-load sessions" + "delta on high-load" markers
//     need bio-filter on session entries. Same instrumentation gap
//     as Stage 1 active-state. Marked status:"deferred".
//
// Drift behavior: getCurrentStage() reflects CURRENT capacity. If a
// user's data regresses (stops body-area chips, falls below check-in
// frequency, etc.), highestStageMet drops. Honest reflection of present
// state. Stage permanence is not granted; it is maintained.
//
// Stage gating: a stage is fully achieved when ALL its shipped markers
// are met AND no deferred markers gate the stage. If any markers are
// status:"deferred", the stage cannot be fully crossed yet — by design.
// Display surfaces should show deferred markers as "system still
// building" rather than as failures by the user.

// — TUNABLE THRESHOLDS — sign-off pending; first-pass values from spec —
const STAGE_THRESHOLDS = Object.freeze({
  // Stage 1 — NOTICING
  S1_BODY_AREA_SESSIONS_MIN: 5,
  S1_BODY_AREA_WINDOW_DAYS: 90,

  // Stage 2 — NAMING
  S2_DISTINCT_CHIPS_MIN: 5,
  S2_DISTINCT_CHIPS_WINDOW_DAYS: 30,
  S2_CHECKINS_PER_WEEK_MIN: 2,
  S2_CHECKINS_SUSTAINED_WEEKS: 2,

  // Stage 3 — ANTICIPATING (gated on Trigger Profile + Pre-event Brief)
  S3_TRIGGERS_NAMED_MIN: 3,
  S3_PRE_EVENT_BRIEFS_MIN: 1,
  S3_PRE_EVENT_WINDOW_DAYS: 14,
  S3_DELTA_ON_TRIGGER_SESSIONS_MIN: 1.5,

  // Stage 4 — RECOGNIZING
  S4_PATTERN_ACCEPTANCE_RATE_MIN: 0.5,
  S4_PATTERN_ACCEPTANCE_LOOKBACK: 5,
  S4_SELF_INITIATED_DISRUPTOR_MIN: 1,
  S4_SELF_INITIATED_WINDOW_DAYS: 30,

  // Stage 5 — HOLDING
  S5_HIGH_LOAD_SESSIONS_MIN: 5,
  S5_HIGH_LOAD_WINDOW_DAYS: 60,
  S5_HIGH_LOAD_DELTA_MIN: 2.0,
  S5_RECOVERY_TREND_LOOKBACK_DAYS: 30,
});

// — Marker computation helpers — pure functions, all read-only —

// Helper: count sessions in last N days where bodyScanTension is non-null
// AND specific (between 1 and BODY_SCAN_AREAS.length - 1 areas tagged).
// "Specific" excludes both the no-tap path (null) and the all-areas case
// (which functions as "everywhere" — the opposite of specificity).
const _s1CountSpecificBodyAreaSessions = (windowDays = STAGE_THRESHOLDS.S1_BODY_AREA_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return sessions.filter(s => {
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < cutoff) return false;
      const tension = s.bodyScanTension;
      if (!tension || typeof tension !== "object") return false;
      const areaCount = Object.keys(tension).length;
      // Specific = at least 1 area, fewer than all 6. "All 6" reads as
      // "everywhere" which is the opposite of the noticing-specificity
      // signal Stage 1 is measuring.
      return areaCount >= 1 && areaCount < BODY_SCAN_AREAS.length;
    }).length;
  } catch { return 0; }
};

// Helper: count distinct preState chip values across sessions in last N days.
// Reframe + Body Scan + Breathe sessions all persist preState when the user
// selected a chip at session start.
const _s2CountDistinctChips = (windowDays = STAGE_THRESHOLDS.S2_DISTINCT_CHIPS_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    const chips = new Set();
    sessions.forEach(s => {
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < cutoff) return;
      if (s.preState && typeof s.preState === "string") chips.add(s.preState.trim().toLowerCase());
    });
    return chips.size;
  } catch { return 0; }
};

// Helper: compute the longest run of consecutive weeks where the user did
// at least N check-ins per week. Used for Stage 2 sustained-consistency.
// Returns the length of that run in weeks (e.g., 2 means "2+ check-ins per
// week for the last 2 consecutive weeks").
const _s2LongestSustainedCheckinRun = (perWeekMin = STAGE_THRESHOLDS.S2_CHECKINS_PER_WEEK_MIN) => {
  try {
    // READ PATH (audit philosophy v1.3 Layer 2.39 Path A migration, May 8 2026):
    // stillform_checkin_history is in SECURE_KEYS and now actually encrypted at rest.
    // Writes flow through appendDailyLoopHistory's secure branch → secureWrite →
    // encrypted envelope. Reads via secureRead return the decrypted array
    // primed by primeSecureCache at boot.
    const raw = secureRead("stillform_checkin_history", []);
    if (!Array.isArray(raw) || raw.length === 0) return 0;
    // Group by ISO week (sunday-anchored). Use ISO date string normalized to
    // a week-start key: monday of the week containing the timestamp.
    const weekKey = (ts) => {
      const d = new Date(ts);
      if (Number.isNaN(d.getTime())) return null;
      const day = d.getDay(); // 0=Sun..6=Sat
      const mondayOffset = day === 0 ? -6 : 1 - day;
      const monday = new Date(d);
      monday.setDate(d.getDate() + mondayOffset);
      monday.setHours(0, 0, 0, 0);
      // Use TimeKeeper.clockDayOf to extract local date — never .toISOString().slice
      // (which would silently extract UTC and bleed across timezone boundaries).
      return TimeKeeper.clockDayOf(monday);
    };
    const weekCounts = new Map();
    raw.forEach(r => {
      const k = weekKey(r.timestamp || r.date);
      if (k) weekCounts.set(k, (weekCounts.get(k) || 0) + 1);
    });
    // Sort weeks chronologically and walk for longest consecutive run.
    const weeks = [...weekCounts.keys()].sort();
    let longest = 0, current = 0;
    let prevWeek = null;
    for (const w of weeks) {
      const meets = weekCounts.get(w) >= perWeekMin;
      if (!meets) { current = 0; prevWeek = w; continue; }
      if (prevWeek) {
        const prevDate = new Date(prevWeek);
        const thisDate = new Date(w);
        const diffWeeks = Math.round((thisDate.getTime() - prevDate.getTime()) / (7 * 24 * 60 * 60 * 1000));
        current = diffWeeks === 1 ? current + 1 : 1;
      } else {
        current = 1;
      }
      if (current > longest) longest = current;
      prevWeek = w;
    }
    return longest;
  } catch { return 0; }
};

// Helper: pattern acceptance rate over the last N surfaced patterns.
// "Surfaced" = state ever transitioned out of new (was prompted to user).
// Acceptance = state === ACCEPTED. Dismiss = DISMISSED_ONCE or CLOSED.
const _s4PatternAcceptanceRate = (lookback = STAGE_THRESHOLDS.S4_PATTERN_ACCEPTANCE_LOOKBACK) => {
  try {
    const detections = getPatternDetectionsFromStorage();
    if (!Array.isArray(detections) || detections.length === 0) return { rate: 0, count: 0 };
    // Most recent surfaced detections — those with state past initial.
    const surfaced = detections
      .filter(d => d && d.state && d.state !== "active" || (d && d.surfacedAt))
      .slice(-lookback);
    if (surfaced.length === 0) return { rate: 0, count: 0 };
    const accepted = surfaced.filter(d => d.state === PATTERN_STATES.ACCEPTED).length;
    return { rate: accepted / surfaced.length, count: surfaced.length };
  } catch { return { rate: 0, count: 0 }; }
};

// Helper: count Disruptor sessions launched WITHOUT a prompted pattern
// (patternId === null means user hit Disruptor self-initiated).
const _s4SelfInitiatedDisruptorCount = (windowDays = STAGE_THRESHOLDS.S4_SELF_INITIATED_WINDOW_DAYS) => {
  try {
    const sessions = getDisruptorSessionsFromStorage();
    if (!Array.isArray(sessions)) return 0;
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return sessions.filter(s => {
      if (!s || s.patternId) return false;
      const t = new Date(s.timestamp || 0).getTime();
      return !Number.isNaN(t) && t >= cutoff;
    }).length;
  } catch { return 0; }
};

// Stage 3 — count of triggers in the user's profile.
const _s3CountTriggers = () => {
  try { return (getTriggerProfile()?.triggers || []).length; } catch { return 0; }
};

// Stage 4 — count of sessions where the user self-flagged a pattern at
// What Shifted close. Activates the marker tracking user catching their own
// patterns (vs. system-only detection). Threshold 1 — single instance crosses.
const _s4UserFlaggedPatternCount = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return 0;
    return sessions.filter(s => s?.flaggedPattern && typeof s.flaggedPattern === "string").length;
  } catch { return 0; }
};

// Format user-flagged patterns from recent session history for AI context.
// Used by Reframe + brief generators (Today's Brief, Pre-event Brief, EOD).
// Tells the AI which patterns the user has caught themselves running so
// the AI reinforces the catch rather than redundantly surfacing the pattern.
// Returns null when no flags exist — callers should treat null as "skip".
const formatUserFlaggedPatternsForAI = (lookback = 15) => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return null;
    const recent = sessions.slice(-lookback).filter(s => s?.flaggedPattern);
    if (!recent.length) return null;
    const counts = {};
    recent.forEach(s => { counts[s.flaggedPattern] = (counts[s.flaggedPattern] || 0) + 1; });
    const top = Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 3);
    const fmt = top.map(([p, n]) => n > 1 ? `${p} (${n}x)` : p).join(", ");
    return `User has self-flagged catching these patterns recently: ${fmt}. They are doing their own metacognitive observation — reinforce the catch, do not surface these patterns as if naming them first.`;
  } catch { return null; }
};

// Stage 3 — Pre-event Briefs used in the last N days.
const _s3CountPreEventBriefs = (windowDays = STAGE_THRESHOLDS.S3_PRE_EVENT_WINDOW_DAYS) => {
  try {
    const briefs = secureRead(PRE_EVENT_BRIEFS_STORAGE_KEY, []);
    if (!Array.isArray(briefs)) return 0;
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return briefs.filter(b => {
      const t = new Date(b?.generatedAt || 0).getTime();
      return !Number.isNaN(t) && t >= cutoff;
    }).length;
  } catch { return 0; }
};

// Stage 3 — average pre→post delta on sessions tagged with a known trigger.
// Returns { avg, count } so the marker can show the value when count >= 3
// (need at least a small sample before the average is meaningful).
const _s3AvgDeltaOnTriggerSessions = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return { avg: 0, count: 0 };
    const tagged = sessions.filter(s => s?.triggerId && Number.isFinite(s.delta));
    if (!tagged.length) return { avg: 0, count: 0 };
    const sum = tagged.reduce((acc, s) => acc + s.delta, 0);
    return { avg: sum / tagged.length, count: tagged.length };
  } catch { return { avg: 0, count: 0 }; }
};

// Stage 1 — count of days where the user logged a morning check-in but did
// NOT enter any tool that day. Per the marker definition: "Times you saw it
// and chose without a tool." The check-in itself IS the metacognitive
// noticing act (state named via energy/mood/bio chips). A day where they
// noticed but didn't escalate to a tool intervention is autonomous regulation
// — the practice working as intended.
const _s1CountAutonomousExits = (windowDays = 30) => {
  try {
    const checkins = secureRead("stillform_checkin_history", []);
    if (!Array.isArray(checkins) || !checkins.length) return 0;
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    // Build set of stillformDay strings where ANY tool session occurred.
    const toolDays = new Set();
    if (Array.isArray(sessions)) {
      sessions.forEach(s => {
        try {
          const t = new Date(s?.timestamp || 0).getTime();
          if (Number.isNaN(t) || t < cutoff) return;
          const day = TimeKeeper.stillformDayOf(s.timestamp);
          if (day) toolDays.add(day);
        } catch {}
      });
    }
    // Count check-in days within window that are NOT in toolDays.
    let autonomousCount = 0;
    const seenDays = new Set();
    checkins.forEach(c => {
      try {
        const t = new Date(c?.timestamp || c?.date || 0).getTime();
        if (Number.isNaN(t) || t < cutoff) return;
        const day = c?.date || TimeKeeper.stillformDayOf(c?.timestamp);
        if (!day || seenDays.has(day)) return;
        seenDays.add(day);
        if (!toolDays.has(day)) autonomousCount++;
      } catch {}
    });
    return autonomousCount;
  } catch { return 0; }
};

// Stage 1 — sessions where the user entered with bio-filter signaling
// "activated" (i.e., they came in during an actual activated moment, not
// routine practice). Reads the bioFilter snapshot now persisted on every
// session entry (see appendSessionToStorage).
const _s1CountActiveStateSessions = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return 0;
    return sessions.filter(s => {
      if (!s?.bioFilter) return false;
      return String(s.bioFilter).toLowerCase().split(",").map(t => t.trim()).includes("activated");
    }).length;
  } catch { return 0; }
};

// Stage 5 — does a session's bioFilter snapshot indicate high-load hardware?
// Any non-clear bio-filter token signals hardware compromise. The bioFilter
// field is auto-attached to every session via appendSessionToStorage.
const _s5SessionIsHighLoad = (s) => {
  if (!s?.bioFilter) return false;
  const tokens = String(s.bioFilter).split(",").map(t => t.trim()).filter(Boolean);
  return tokens.some(t => t !== "clear");
};

// Stage 5 — count of high-load sessions in the last N days.
const _s5HighLoadSessionCount = (windowDays = STAGE_THRESHOLDS.S5_HIGH_LOAD_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return 0;
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return sessions.filter(s => {
      if (!_s5SessionIsHighLoad(s)) return false;
      const t = new Date(s.timestamp || 0).getTime();
      return !Number.isNaN(t) && t >= cutoff;
    }).length;
  } catch { return 0; }
};

// Stage 5 — average pre→post delta on high-load sessions.
// Returns { avg, count } so the marker can show value when count >= 3.
const _s5AvgDeltaOnHighLoadSessions = (windowDays = STAGE_THRESHOLDS.S5_HIGH_LOAD_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    if (!Array.isArray(sessions)) return { avg: 0, count: 0 };
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    const matching = sessions.filter(s => {
      if (!_s5SessionIsHighLoad(s) || !Number.isFinite(s.delta)) return false;
      const t = new Date(s.timestamp || 0).getTime();
      return !Number.isNaN(t) && t >= cutoff;
    });
    if (!matching.length) return { avg: 0, count: 0 };
    const sum = matching.reduce((acc, s) => acc + s.delta, 0);
    return { avg: sum / matching.length, count: matching.length };
  } catch { return { avg: 0, count: 0 }; }
};

// Helper: recovery trend — does pre→post delta improve over time on
// sessions where the user has rated both pre and post? Stage 5 marker
// for "recovery time trending downward." Operationalized as "average
// delta in last half of window > average delta in first half" — improving.
const _s5RecoveryTrendImproving = (lookbackDays = STAGE_THRESHOLDS.S5_RECOVERY_TREND_LOOKBACK_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(lookbackDays);
    const rated = sessions
      .filter(s => {
        const t = new Date(s.timestamp || 0).getTime();
        if (Number.isNaN(t) || t < cutoff) return false;
        return typeof s.preRate === "number" && typeof s.postRate === "number";
      })
      .sort((a, b) => new Date(a.timestamp || 0).getTime() - new Date(b.timestamp || 0).getTime());
    if (rated.length < 4) return null; // not enough data
    const half = Math.floor(rated.length / 2);
    const firstHalf = rated.slice(0, half);
    const secondHalf = rated.slice(half);
    const avgDelta = arr => arr.reduce((sum, s) => sum + (s.postRate - s.preRate), 0) / arr.length;
    const firstAvg = avgDelta(firstHalf);
    const secondAvg = avgDelta(secondHalf);
    return { improving: secondAvg > firstAvg, firstAvg, secondAvg };
  } catch { return null; }
};

