// Calendar screenshot extraction — POST to vision endpoint, get structured events.
// Reuses the same authenticated POST pattern as org endpoints.
const sbExtractCalendarScreenshot = async ({ imageData, imageMime, tzOffsetMinutes, referenceDate }) => {
  const session = sbGetSession();
  if (!session?.access_token) return { ok: false, error: "Not signed in" };
  try {
    const url = (typeof window !== "undefined" && window.location?.hostname === "stillformapp.com")
      ? "https://stillformapp.com/.netlify/functions/calendar-screenshot-extract"
      : "/.netlify/functions/calendar-screenshot-extract";
    const res = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${session.access_token}`
      },
      body: JSON.stringify({
        image_data: imageData,
        image_mime: imageMime,
        tz_offset_minutes: tzOffsetMinutes,
        reference_date: referenceDate
      })
    });
    const data = await res.json().catch(() => ({ error: "Bad response" }));
    if (!res.ok) return { ok: false, error: data?.error || `HTTP ${res.status}` };
    return data;
  } catch (err) {
    return { ok: false, error: err?.message || "Network error" };
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// ─── ENCRYPTION UTILITY ──────────────────────────────────────────────────────
// Device-local AES-GCM encryption for sensitive conversation data.
// Key is generated once per device and stored in IndexedDB.
// Data is encrypted at rest in localStorage — not readable by other services.
const CryptoStore = (() => {
  const DB_NAME = "stillform_keys";
  const KEY_NAME = "device_key";

  const getDB = () => new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = e => e.target.result.createObjectStore("keys");
    req.onsuccess = e => resolve(e.target.result);
    req.onerror = () => reject(req.error);
  });

  const getOrCreateKey = async () => {
    try {
      const db = await getDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction("keys", "readwrite");
        const store = tx.objectStore("keys");
        const getReq = store.get(KEY_NAME);
        getReq.onsuccess = async () => {
          if (getReq.result) { resolve(getReq.result); return; }
          const key = await crypto.subtle.generateKey({ name: "AES-GCM", length: 256 }, true, ["encrypt", "decrypt"]);
          store.put(key, KEY_NAME);
          resolve(key);
        };
        getReq.onerror = () => reject(getReq.error);
      });
    } catch { return null; }
  };

  const encrypt = async (data) => {
    try {
      const key = await getOrCreateKey();
      if (!key) return data; // fallback to plain if crypto unavailable
      const iv = crypto.getRandomValues(new Uint8Array(12));
      const encoded = new TextEncoder().encode(JSON.stringify(data));
      const encrypted = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, encoded);
      return { __enc: true, iv: Array.from(iv), data: Array.from(new Uint8Array(encrypted)) };
    } catch { return data; }
  };

  const decrypt = async (stored) => {
    try {
      if (!stored?.__enc) return stored;
      const key = await getOrCreateKey();
      if (!key) return null;
      const iv = new Uint8Array(stored.iv);
      const data = new Uint8Array(stored.data);
      const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, data);
      return JSON.parse(new TextDecoder().decode(decrypted));
    } catch { return null; }
  };

  // May 7, 2026: forensic deletion completeness. The "Delete account" flow at the
  // bottom of Settings was clearing localStorage + Supabase cloud data but leaving
  // the AES-GCM device key in IndexedDB. Practically harmless (cloud data is gone,
  // there's nothing left to decrypt), but on a shared device the key persisted.
  // Drops the entire stillform_keys database in one call rather than iterating.
  // Resolves on success or absence — never rejects so it can't block the wipe path.
  const deleteKey = () => new Promise((resolve) => {
    try {
      const req = indexedDB.deleteDatabase(DB_NAME);
      req.onsuccess = () => resolve(true);
      req.onerror = () => resolve(false);
      req.onblocked = () => resolve(false);
    } catch { resolve(false); }
  });

  return { encrypt, decrypt, deleteKey };
})();

// ─── SecureStore — IndexedDB fallback for secureSet/secureGet ────────────────
// Why: localStorage caps at ~5–10MB per origin. When a long conversation hits
// the cap, secureSet's localStorage.setItem throws QuotaExceededError, the
// catch block swallows it, and the message is silently lost. Routing the write
// to IndexedDB on overflow preserves the conversation. IndexedDB has ~50% disk
// quota (gigabytes). Same AES-GCM encryption — encryption happens in secureSet
// before this module is reached, so the stored blob is identical either way.
const SecureStore = (() => {
  const DB_NAME = "stillform_secure";
  const STORE = "secure_data";

  const getDB = () => new Promise((resolve, reject) => {
    try {
      const req = indexedDB.open(DB_NAME, 1);
      req.onupgradeneeded = e => e.target.result.createObjectStore(STORE);
      req.onsuccess = e => resolve(e.target.result);
      req.onerror = () => reject(req.error);
    } catch (e) { reject(e); }
  });

  const set = async (key, value) => {
    try {
      const db = await getDB();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE, "readwrite");
        const store = tx.objectStore(STORE);
        const req = store.put(value, key);
        req.onsuccess = () => resolve(true);
        req.onerror = () => reject(req.error);
      });
    } catch { return false; }
  };

  const get = async (key) => {
    try {
      const db = await getDB();
      return new Promise((resolve) => {
        const tx = db.transaction(STORE, "readonly");
        const store = tx.objectStore(STORE);
        const req = store.get(key);
        req.onsuccess = () => resolve(req.result === undefined ? null : req.result);
        req.onerror = () => resolve(null);
      });
    } catch { return null; }
  };

  const remove = async (key) => {
    try {
      const db = await getDB();
      return new Promise((resolve) => {
        const tx = db.transaction(STORE, "readwrite");
        const store = tx.objectStore(STORE);
        const req = store.delete(key);
        req.onsuccess = () => resolve(true);
        req.onerror = () => resolve(false);
      });
    } catch { return false; }
  };

  // May 7, 2026: forensic deletion completeness — the "Delete account" flow needs
  // to wipe overflow blobs in IndexedDB along with localStorage. Long Reframe
  // conversations that overflowed localStorage's 5–10MB cap end up here; without
  // this they survive the delete-all-data flow on a shared device. Drops the
  // entire stillform_secure database in one call. Resolves on success or absence
  // so it never blocks the wipe path.
  const clear = () => new Promise((resolve) => {
    try {
      const req = indexedDB.deleteDatabase(DB_NAME);
      req.onsuccess = () => resolve(true);
      req.onerror = () => resolve(false);
      req.onblocked = () => resolve(false);
    } catch { resolve(false); }
  });

  return { set, get, remove, clear };
})();

// Encrypted get/set for sensitive keys.
// Tries localStorage first (fast), falls through to IndexedDB on overflow/error.
// Reads check localStorage first, then IndexedDB. Both stores hold the same
// encrypted blob shape — no decryption-path difference.
async function secureGet(key) {
  try {
    const raw = localStorage.getItem(key);
    if (raw) {
      const parsed = JSON.parse(raw);
      if (parsed?.__enc) return await CryptoStore.decrypt(parsed);
      return parsed;
    }
  } catch {}
  // localStorage empty or unreadable — try IndexedDB fallback
  try {
    const fallback = await SecureStore.get(key);
    if (fallback) {
      if (fallback?.__enc) return await CryptoStore.decrypt(fallback);
      return fallback;
    }
  } catch {}
  return null;
}
async function secureSet(key, value) {
  let encrypted;
  try {
    encrypted = await CryptoStore.encrypt(value);
  } catch {
    return; // encryption failure — caller can't recover, give up cleanly
  }
  // Try localStorage first
  try {
    localStorage.setItem(key, JSON.stringify(encrypted));
    // Success — also clear any stale IndexedDB copy for this key so reads stay consistent
    SecureStore.remove(key).catch(() => {});
    return;
  } catch {
    // Quota exceeded or storage unavailable — fall through to IndexedDB
  }
  try {
    await SecureStore.set(key, encrypted);
  } catch {
    // Both stores failed. Write a single non-blocking marker for diagnostics.
    // Caller doesn't get an exception — current session continues normally —
    // but at least the failure is visible if the user reports a missing message.
    try {
      sessionStorage.setItem("stillform_secure_set_failed_at", new Date().toISOString());
    } catch {}
  }
}

// ─── readJSON / writeJSON — encrypted JSON helpers for sensitive keys ────────
// Wraps secureSet/secureGet with the JSON-parse pattern that's used everywhere
// in the codebase. Replaces:
//   const x = JSON.parse(localStorage.getItem(KEY) || "null");
//   localStorage.setItem(KEY, JSON.stringify(value));
// with:
//   const x = await readJSON(KEY);
//   await writeJSON(KEY, value);
//
// readJSON checks the encrypted store first (secureGet), then falls back to
// plain localStorage during the build window — once all call sites are migrated,
// the plain-fallback path can be removed entirely.
//
// writeJSON encrypts via secureSet and removes any stale plain-text copy.
async function readJSON(key, fallback = null) {
  try {
    const enc = await secureGet(key);
    if (enc !== null && enc !== undefined) return enc;
  } catch {}
  // Plain-text fallback — present only during build/migration window.
  // Once all sensitive keys are migrated, this branch can be removed.
  try {
    const raw = localStorage.getItem(key);
    if (raw === null || raw === undefined) return fallback;
    return JSON.parse(raw);
  } catch {
    return fallback;
  }
}

async function writeJSON(key, value) {
  await secureSet(key, value);
  // Remove any stale plain-text copy so subsequent reads come from the
  // encrypted store. secureSet also clears the IndexedDB stale copy.
  try { localStorage.removeItem(key); } catch {}
}

// ─── SecureCache — in-memory plaintext cache for synchronous reads ───────────
// Why this exists: secureGet/secureSet are async (crypto.subtle is Promise-based).
// But the codebase has many synchronous read patterns inside React renders,
// inline IIFEs, and effect setup blocks where we cannot await. Without sync
// reads, every encrypt-then-read cycle introduces visible flicker on cold load.
//
// The fix: at app boot, decrypt all sensitive keys once into an in-memory map.
// All subsequent reads are sync (return from map). Writes update both the
// in-memory map (sync) and the encrypted persistence layer (async, fire-and-
// forget). The decryption key is held in CryptoStore (already in memory after
// first use), so writes don't re-derive the key per call.
//
// Boot flow: primeSecureCache(SENSITIVE_KEYS) runs before the app renders.
// The splash screen blocks render until the prime completes. Cost: one-time
// ~50-200ms latency at cold boot. Benefit: zero flicker on every screen that
// reads sensitive data, and no render-layer refactor across the whole app.
//
// Migration: primeSecureCache reads encrypted storage first (secureGet); if
// no encrypted blob exists, falls back to plain localStorage and triggers an
// immediate encrypted re-write so the next boot reads from encrypted storage.
const SecureCache = (() => {
  // Map<storageKey, parsedValue>
  const cache = new Map();
  // Has primeSecureCache run successfully? Used to gate sync reads.
  let primed = false;

  const isPrimed = () => primed;
  const markPrimed = () => { primed = true; };

  const has = (key) => cache.has(key);
  const get = (key) => cache.get(key);
  const set = (key, value) => { cache.set(key, value); };
  const del = (key) => { cache.delete(key); };

  return { isPrimed, markPrimed, has, get, set, del };
})();

// List of sensitive keys to prime + keep encrypted at rest.
// Adding a key here makes it (a) decrypted into SecureCache at boot,
// (b) read sync via secureRead, (c) written sync via secureWrite (with async
// encrypted persistence behind the scenes), (d) auto-migrated from plain text
// on first boot after this code ships.
const SECURE_KEYS = [
  "stillform_journal",
  "stillform_signal_profile",
  "stillform_bias_profile",
  "stillform_trigger_profile",
  "stillform_checkin_history",
  "stillform_eod_history",
  "stillform_eod_artifacts",
  "stillform_todays_briefs",
  "stillform_pre_event_briefs",
  "stillform_move_card_history",
  "stillform_communication_events",
  "stillform_tool_debriefs",
  "stillform_focus_check_history",
  "stillform_feelstate",
  "stillform_sessions",
  "stillform_saved_reframes",
  "stillform_ai_session_notes",
  "stillform_grounding_data",
  "stillform_bio_filter",
  "stillform_session_entry_context",
  "stillform_loop_nudge_events"
];

// Prime the SecureCache at app boot. Returns a Promise that resolves when
// every sensitive key has been decrypted into memory (or a plaintext fallback
// has been read + immediately re-encrypted for next boot).
async function primeSecureCache() {
  for (const key of SECURE_KEYS) {
    try {
      const encryptedRaw = localStorage.getItem(key);
      if (encryptedRaw) {
        const parsed = JSON.parse(encryptedRaw);
        if (parsed?.__enc) {
          // Already encrypted — decrypt and cache
          const decrypted = await CryptoStore.decrypt(parsed);
          SecureCache.set(key, decrypted);
        } else {
          // Plain text — migrate by re-encrypting in place
          SecureCache.set(key, parsed);
          // Fire-and-forget re-encrypt; if it fails, plain text remains and
          // we try again on next boot. No data is lost in either case.
          secureSet(key, parsed).catch(() => {});
        }
        continue;
      }
      // No localStorage entry — try IndexedDB fallback (large blobs)
      const fallback = await SecureStore.get(key);
      if (fallback) {
        const decrypted = fallback?.__enc ? await CryptoStore.decrypt(fallback) : fallback;
        SecureCache.set(key, decrypted);
      }
    } catch {
      // Per-key failure shouldn't block the rest of boot. Cache stays empty
      // for this key; secureRead returns the fallback for the caller.
    }
  }
  SecureCache.markPrimed();
}

// Synchronous read from the in-memory cache. Returns fallback if the key has
// not been primed yet OR was missing from storage. Safe to call inside React
// renders, inline IIFEs, and effect setup blocks.
//
// IMPORTANT: callers must pass a sensible fallback. The intent is that a key
// in SECURE_KEYS is already cached by the time anyone calls secureRead on it.
// If the cache is unprimed (e.g. boot sequence error), we return fallback
// rather than throwing — the app keeps running, the user sees default state,
// and the issue is non-fatal.
function secureRead(key, fallback = null) {
  if (SecureCache.has(key)) return SecureCache.get(key);
  return fallback;
}

// Synchronous-from-caller write. Updates the in-memory cache immediately so
// subsequent secureRead calls see the new value with no delay. The encrypted
// persistence write is fire-and-forget — writes will fail silently to the
// secureSet error path but the cache still holds the new value for the rest
// of the session.
//
// This is intentional: we trade write durability per-call (which would require
// awaiting the encrypted write) for sync semantics that match how the codebase
// is structured. If a write fails to persist, the next boot will re-read from
// whatever last successfully persisted — same as any other write failure.
function secureWrite(key, value) {
  SecureCache.set(key, value);
  // Persist async; suppress errors so caller doesn't have to await
  secureSet(key, value).catch(() => {});
}

// Synchronous delete — cache + persistence
function secureDelete(key) {
  SecureCache.del(key);
  try { localStorage.removeItem(key); } catch {}
  SecureStore.remove(key).catch(() => {});
}

// ─── IMAGE OCR UTILITY ───────────────────────────────────────────────────────
// Loads Tesseract.js lazily from CDN — only when user taps the upload button
// Extracts text from screenshots (emails, texts, social posts) client-side
// No data leaves the device — all processing happens in the browser
// GPT-4o vision handles image reading


