    "figured it out",
    "figured out",
    "found a way",
    "worked out",
    "working out",
    "in a good place",
    "better now",
    "doing better",
    "feel better now",
    "feeling better now",
    "good now",
    "okay now",
    "calmer now",
    "more clear now",
    "relieved",
    "relief",
    "that helped",
